		applyConfigRowVisibility(ColorLockConfig.MANUAL_INCLUDE_FOOD_CONFIG_NAME, show);
		applyConfigRowVisibility(ColorLockConfig.MANUAL_LOCK_AMMUNITION_CONFIG_NAME, show);
