	}

	private JPanel createResultRow(LookupHit hit)
	{
		JPanel row = new JPanel();
		row.setLayout(new BoxLayout(row, BoxLayout.Y_AXIS));
		row.setAlignmentX(Component.LEFT_ALIGNMENT);
		row.setBorder(BorderFactory.createCompoundBorder(
			BorderFactory.createMatteBorder(0, 0, 1, 0, new Color(55, 55, 62)),
			BorderFactory.createEmptyBorder(8, 4, 8, 4)));

		addLookupHeadingRow(row, hit.name.trim() + ":");

		JLabel iconLabel = new JLabel();
		iconLabel.setPreferredSize(new Dimension(ICON_SLOT, ICON_SLOT));
		iconLabel.setHorizontalAlignment(JLabel.CENTER);
		iconLabel.setVerticalAlignment(JLabel.CENTER);
		itemManager.getImage(hit.itemId).addTo(iconLabel);

		JPanel bodyColumn = new JPanel();
		bodyColumn.setLayout(new BoxLayout(bodyColumn, BoxLayout.Y_AXIS));
		bodyColumn.setOpaque(false);

		ManifestItem listed = hit.manifestRow;
		boolean hasColors = listed != null && !listed.getUsableColors().isEmpty();
		Font smallUi = bodyColumn.getFont().deriveFont(Font.PLAIN, 11f);
		Color muted = new Color(150, 150, 160);

		boolean isOptOut = listed != null && hasColors && !ManifestRules.isLockEnforced(listed);

		if (!hasColors)
		{
			JPanel miss = new JPanel(new FlowLayout(FlowLayout.LEFT, 6, 2));
			miss.setOpaque(false);
			JLabel none = new JLabel("not in manifest");
			none.setFont(smallUi);
			none.setForeground(new Color(120, 120, 130));
			miss.add(none);
			bodyColumn.add(miss);
		}
		else if (isOptOut)
		{
			JPanel allRow = new JPanel(new FlowLayout(FlowLayout.LEFT, 6, 2));
			allRow.setOpaque(false);
			JLabel allLbl = new JLabel("All colors");
			allLbl.setFont(bodyColumn.getFont().deriveFont(Font.BOLD, 12f));
			allLbl.setForeground(new Color(110, 170, 120));
			allRow.add(allLbl);
			bodyColumn.add(allRow);
		}
		else
		{
			// Per-item palette chips only. Group / crew intersection moved to a future "Group"
			// sidebar tab that will also show group name, member display names, and assignments.
			appendPaletteChipsWrapped(bodyColumn, ManifestRules.usableColorsManifestOrdered(listed));
		}

		row.add(Box.createVerticalStrut(4));

		JPanel iconBody = new JPanel(new BorderLayout(10, 0));
		iconBody.setOpaque(false);
		iconBody.setAlignmentX(Component.LEFT_ALIGNMENT);
		iconBody.add(iconLabel, BorderLayout.WEST);
		iconBody.add(bodyColumn, BorderLayout.CENTER);
		row.add(iconBody);
		attachWikiOpenToLookupRow(row, hit);
		addDropSourcesToggle(row, hit);
		return row;
	}

	private void addDropSourcesToggle(JPanel row, LookupHit hit)
	{
		JPanel sourcesContainer = new JPanel();
		sourcesContainer.setLayout(new BoxLayout(sourcesContainer, BoxLayout.Y_AXIS));
		sourcesContainer.setAlignmentX(Component.LEFT_ALIGNMENT);
		sourcesContainer.setVisible(false);

		JLabel toggle = new JLabel("▶ Drop sources");
		toggle.setFont(toggle.getFont().deriveFont(Font.PLAIN, 11f));
		toggle.setForeground(new Color(110, 140, 200));
		toggle.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
		toggle.setAlignmentX(Component.LEFT_ALIGNMENT);
		toggle.setBorder(BorderFactory.createEmptyBorder(4, 4, 0, 0));

		final boolean[] loaded = {false};
		toggle.addMouseListener(new MouseAdapter()
		{
			@Override
			public void mouseClicked(MouseEvent e)
			{
				if (!SwingUtilities.isLeftMouseButton(e))
				{
					return;
				}
				e.consume();
				if (sourcesContainer.isVisible())
				{
					sourcesContainer.setVisible(false);
					toggle.setText("▶ Drop sources");
					return;
				}
				if (!loaded[0])
				{
					loaded[0] = true;
					toggle.setText("▼ Loading…");
					manifestStore.fetchItemDropSourcesAsync(hit.itemId, sources ->
						SwingUtilities.invokeLater(() -> {
							sourcesContainer.removeAll();
							if (sources.isEmpty())
							{
								JLabel none = new JLabel("No drop sources available.");
								none.setFont(none.getFont().deriveFont(11f));
								none.setForeground(new Color(150, 150, 160));
								none.setBorder(BorderFactory.createEmptyBorder(2, 8, 2, 0));
								sourcesContainer.add(none);
							}
							else
							{
								for (DropSourceInfo src : sources)
								{
									sourcesContainer.add(buildDropSourceRow(src));
								}
							}
							toggle.setText("▼ Drop sources (" + sources.size() + ")");
							sourcesContainer.setVisible(true);
							sourcesContainer.revalidate();
							sourcesContainer.repaint();
						}));
				}
				else
				{
					sourcesContainer.setVisible(true);
					toggle.setText("▼ Drop sources");
				}
			}
		});

		row.add(toggle);
		row.add(sourcesContainer);
	}

	private static JPanel buildDropSourceRow(DropSourceInfo src)
	{
		JPanel dp = new JPanel(new BorderLayout(6, 0));
		dp.setOpaque(false);
		dp.setAlignmentX(Component.LEFT_ALIGNMENT);
		dp.setBorder(BorderFactory.createEmptyBorder(2, 8, 2, 4));

		String name = src.getMonsterName().isEmpty() ? "(unknown)" : src.getMonsterName();
		JLabel nameLabel = new JLabel(name);
		nameLabel.setFont(nameLabel.getFont().deriveFont(12f));
		nameLabel.setForeground(new Color(210, 210, 210));
		dp.add(nameLabel, BorderLayout.WEST);

		String rarity = src.getRarityLabel().isEmpty()
			? (src.getRarity() > 0 ? String.format("1/%.0f", 1.0 / src.getRarity()) : "")
			: src.getRarityLabel();
		String qty = src.getQuantity().isEmpty() ? "" : " (x" + src.getQuantity() + ")";
		JLabel detail = new JLabel(rarity + qty);
		detail.setFont(detail.getFont().deriveFont(11f));
		detail.setForeground(new Color(150, 150, 160));
		dp.add(detail, BorderLayout.EAST);

		if (isOsrsWikiUrl(src.getMonsterWikiUrl()))
		{
			nameLabel.setForeground(new Color(108, 151, 255));
			nameLabel.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
			nameLabel.setToolTipText("Open wiki page");
			nameLabel.addMouseListener(new MouseAdapter()
			{
				@Override
				public void mouseClicked(MouseEvent e)
				{
					if (SwingUtilities.isLeftMouseButton(e))
					{
						LinkBrowser.browse(src.getMonsterWikiUrl());
					}
				}
			});
		}

		return dp;
	}

	private static boolean isOsrsWikiUrl(String url)
	{
		if (url == null || url.isEmpty())
		{
			return false;
		}
		String lower = url.toLowerCase(Locale.ENGLISH);
		return lower.startsWith("https://oldschool.runescape.wiki/")
			|| lower.startsWith("https://secure.runescape.com/");
	}

	/** Same URL shape as RuneLite Wiki for item lookups (Special:Lookup + utm_source). */
	private static String osrsWikiItemLookupUrl(String name, int canonicalItemId)
	{
		String nm = name == null ? "" : name.trim();
		String enc = URLEncoder.encode(nm, StandardCharsets.UTF_8).replace("+", "%20");
		return "https://oldschool.runescape.wiki/w/Special:Lookup?type=item&id=" + canonicalItemId
			+ "&name=" + enc
			+ "&utm_source=runelite";
	}

	private void openWikiForLookupHit(LookupHit hit)
	{
		clientThread.invokeLater(() ->
		{
			int id = itemManager.canonicalize(hit.itemId);
			ItemComposition def = client.getItemDefinition(id);
			String wikiName = def != null ? Text.removeTags(def.getMembersName()) : "";
			if (wikiName == null || wikiName.trim().isEmpty() || "null".equalsIgnoreCase(wikiName))
			{
				wikiName = hit.name == null ? "" : hit.name.trim();
			}
			String url = osrsWikiItemLookupUrl(wikiName, id);
			SwingUtilities.invokeLater(() -> LinkBrowser.browse(url));
		});
	}

	private void attachWikiOpenToLookupRow(JPanel rowRoot, LookupHit hit)
	{
		rowRoot.setToolTipText("Left-click row: OSRS Wiki");
		MouseAdapter opener = new MouseAdapter()
		{
			@Override
			public void mouseClicked(MouseEvent e)
			{
				if (SwingUtilities.isLeftMouseButton(e))
				{
					openWikiForLookupHit(hit);
				}
			}
		};
		eachSwingDescendant(rowRoot, jc ->
		{
			jc.addMouseListener(opener);
			jc.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
		});
	}

	private static void eachSwingDescendant(Container root, Consumer<JComponent> visit)
	{
		if (root instanceof JComponent)
		{
			visit.accept((JComponent) root);
		}
		for (Component c : root.getComponents())
		{
			if (c instanceof Container)
			{
				eachSwingDescendant((Container) c, visit);
			}
		}
	}

	/** Bold item name full-width above icon row (never beside the sprite). */
	private static void addLookupHeadingRow(JPanel column, String nameWithColonSpace)
	{
		JPanel h = new JPanel(new FlowLayout(FlowLayout.LEFT, 4, 0));
		h.setOpaque(false);
		h.setAlignmentX(Component.LEFT_ALIGNMENT);
		JLabel title = new JLabel(nameWithColonSpace);
		title.setFont(title.getFont().deriveFont(Font.BOLD));
		h.add(title);
		column.add(h);
	}
	/** Fits palette chips inside the sidebar by starting a new row every few chips */
	private static void appendPaletteChipsWrapped(JPanel column, List<String> manifestTokens)
	{
		int cap = paletteChipsPerRow();
		JPanel chipRow = null;
		for (String token : manifestTokens)
		{
			if (token == null || token.trim().isEmpty())
			{
				continue;
			}
			if (chipRow == null || chipRow.getComponentCount() >= cap)
			{
				chipRow = new JPanel(new FlowLayout(FlowLayout.LEFT, 5, 4));
				chipRow.setOpaque(false);
				chipRow.setAlignmentX(Component.LEFT_ALIGNMENT);
				column.add(chipRow);
			}
			chipRow.add(new PaletteChip(token.trim()));
		}
	}

	private static int paletteChipsPerRow()
	{
		int textBudgetPx = PluginPanel.PANEL_WIDTH - ICON_SLOT - 44;
		return Math.max(2, Math.min(10, textBudgetPx / 22));
	}

	private static final java.util.regex.Pattern CHARGED_SUFFIX = java.util.regex.Pattern.compile("\\(\\d+\\)$");

	private static String stripChargedSuffix(String nameLc)
	{
		return CHARGED_SUFFIX.matcher(nameLc).replaceFirst("").trim();
	}

	private static String escapeHtml(String s)
	{
		if (s == null)
		{
			return "";
		}
		return s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;");
	}

	private static JLabel urlLink(final String url)
	{
		JLabel ln = new JLabel("<html><body style='width:220px'><font color=\"#6C97FF\"><u>"
			+ escapeHtml(url)
			+ "</u></font></body></html>");
		ln.setAlignmentX(Component.LEFT_ALIGNMENT);
		ln.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
		ln.setToolTipText("Open in browser");
		ln.addMouseListener(new java.awt.event.MouseAdapter()
		{
			@Override
			public void mouseClicked(java.awt.event.MouseEvent ev)
			{
				LinkBrowser.browse(url);
			}
		});
		return ln;
	}

	/** Color-wheel nav icon: 8 OSRS palette slices, dark padlock-shackle accent. */
	static BufferedImage createNavIcon()
	{
		final int size = 32;
		final int pad = 2;
		final int diameter = size - pad * 2;
		BufferedImage img = new BufferedImage(size, size, BufferedImage.TYPE_INT_ARGB);
		Graphics2D g = img.createGraphics();
		try
		{
			g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

			String[] slices = {"red", "yellow", "green", "blue", "purple", "brown", "black", "white"};
			float sliceDeg = 360f / slices.length;
			for (int i = 0; i < slices.length; i++)
			{
				g.setColor(ColorLockPalette.toUiColor(slices[i]));
				g.fillArc(pad, pad, diameter, diameter, Math.round(90f - i * sliceDeg - sliceDeg), Math.round(sliceDeg) + 1);
			}

			g.setStroke(new java.awt.BasicStroke(1.2f));
			g.setColor(new Color(20, 20, 24, 220));
			g.drawOval(pad, pad, diameter - 1, diameter - 1);

			int hole = 8;
			int hx = size / 2 - hole / 2;
			int hy = size / 2 - hole / 2;
			g.setColor(new Color(30, 30, 35));
			g.fillOval(hx, hy, hole, hole);
			g.setColor(new Color(220, 220, 230, 200));
			g.setStroke(new java.awt.BasicStroke(1.4f));
			g.drawArc(hx + 1, hy - 2, hole - 2, hole - 1, 20, 140);
		}
		finally
		{
			g.dispose();
		}
		return img;
	}

	private static final class LookupHit
	{
		final int itemId;
		final String name;
		final int canon;
		final ManifestItem manifestRow;

		LookupHit(int itemId, String name, int canon, ManifestItem manifestRow)
		{
			this.itemId = itemId;
			this.name = name;
			this.canon = canon;
			this.manifestRow = manifestRow;
		}
	}

	/** Rounded palette swatch — color fill only; tooltip shows the palette name. */
	private static final class PaletteChip extends JPanel
	{
		private static final int SWATCH = 18;

		private final Color fill;
		private final int arc;

		PaletteChip(String paletteToken)
		{
			setOpaque(false);
			String t = paletteToken == null ? "" : paletteToken.trim();
			String keyLc = t.toLowerCase(Locale.ENGLISH);
			fill = ColorLockPalette.toUiColor(t.isEmpty() ? null : keyLc);
			String tip = t.isEmpty() ? ColorLockPalette.abbreviation(null) : t;
			setToolTipText(tip);
			Dimension d = new Dimension(SWATCH, SWATCH);
			setPreferredSize(d);
			setMinimumSize(d);
			setMaximumSize(d);
			arc = SWATCH;
		}

		@Override
		protected void paintComponent(Graphics g)
		{
			super.paintComponent(g);
			Graphics2D g2 = (Graphics2D) g.create();
			try
			{
				g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
				int w = getWidth();
				int h = getHeight();
				g2.setColor(fill);
				g2.fillRoundRect(0, 0, w - 1, h - 1, arc, arc);
				g2.setColor(new Color(45, 45, 52));
				g2.drawRoundRect(0, 0, w - 1, h - 1, arc, arc);
			}
			finally
			{
				g2.dispose();
			}
		}
	}
}

package com.osrscolorlock.colorlock;

import com.google.gson.Gson;
import com.google.gson.annotations.SerializedName;

import java.io.IOException;
import java.io.Reader;
import java.io.Writer;
import java.nio.charset.StandardCharsets;
import java.nio.file.AtomicMoveNotSupportedException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.StandardCopyOption;
import java.time.Instant;
import java.util.Collections;
import java.util.List;

import net.runelite.client.RuneLite;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/** Persists the last successful items manifest under {@link RuneLite#RUNELITE_DIR}/color-lock-helper/. */
final class ManifestDiskCache
{
	private static final Logger log = LoggerFactory.getLogger(ManifestDiskCache.class);
	private static final int CACHE_FORMAT_VERSION = 1;

	private final Gson gson;
	private final Path cacheFile;

	ManifestDiskCache(Gson gson)
	{
		this(gson, defaultCachePath());
	}

	ManifestDiskCache(Gson gson, Path cacheFile)
	{
		this.gson = gson;
		this.cacheFile = cacheFile;
	}

	static Path defaultCachePath()
	{
		return Paths.get(RuneLite.RUNELITE_DIR.getAbsolutePath(), "color-lock-helper", "items-manifest.json");
	}

	Snapshot load()
	{
		if (!Files.isRegularFile(cacheFile))
		{
			return null;
		}
		try (Reader reader = Files.newBufferedReader(cacheFile, StandardCharsets.UTF_8))
		{
			Snapshot snap = gson.fromJson(reader, Snapshot.class);
			if (snap == null || snap.items == null || snap.items.isEmpty())
			{
				return null;
			}
			return snap;
		}
		catch (IOException | RuntimeException e)
		{
			log.warn("Could not read color-lock manifest disk cache at {}", cacheFile, e);
			return null;
		}
	}

	void save(String sourceUrl, int schemaVersion, List<ManifestItem> items)
	{
		if (items == null || items.isEmpty())
		{
			return;
		}
		Snapshot snap = new Snapshot();
		snap.cacheFormatVersion = CACHE_FORMAT_VERSION;
		snap.savedAt = Instant.now().toString();
		snap.sourceUrl = sourceUrl == null ? "" : sourceUrl;
		snap.schemaVersion = schemaVersion;
		snap.items = items;

		Path parent = cacheFile.getParent();
		Path tmp = cacheFile.resolveSibling(cacheFile.getFileName().toString() + ".tmp");
		try
		{
			if (parent != null)
			{
				Files.createDirectories(parent);
			}
			try (Writer writer = Files.newBufferedWriter(tmp, StandardCharsets.UTF_8))
			{
				gson.toJson(snap, writer);
			}
			try
			{
				Files.move(tmp, cacheFile, StandardCopyOption.REPLACE_EXISTING, StandardCopyOption.ATOMIC_MOVE);
			}
			catch (AtomicMoveNotSupportedException e)
			{
				Files.move(tmp, cacheFile, StandardCopyOption.REPLACE_EXISTING);
			}
			log.debug("Wrote color-lock manifest disk cache ({} items, schema {})", items.size(), schemaVersion);
		}
		catch (IOException e)
		{
			log.warn("Could not write color-lock manifest disk cache at {}", cacheFile, e);
			try
			{
				Files.deleteIfExists(tmp);
			}
			catch (IOException ignored)
			{
			}
		}
	}

	static final class Snapshot
	{
		@SerializedName("cacheFormatVersion")
		int cacheFormatVersion;

		@SerializedName("savedAt")
		String savedAt;

		@SerializedName("sourceUrl")
		String sourceUrl;

		@SerializedName("schemaVersion")
		int schemaVersion;

		@SerializedName("items")
		List<ManifestItem> items = Collections.emptyList();
	}
}

package com.osrscolorlock.colorlock;

import com.google.gson.annotations.SerializedName;

import java.util.ArrayList;
import java.util.Collections;
import java.util.LinkedHashSet;
import java.util.List;

/** Minimum fields described in DATA_CONTRACT.md; Gson ignores extras. */
public class ManifestItem
{
	private int id;
	private String name;
	private String category;
	@SerializedName(value = "schemaVersion", alternate = {"schema_version"})
	private Number schemaVersion;
	@SerializedName(value = "usableColors", alternate = {"usable_colors"})
	private List<String> usableColors;

	/**
	 * When {@code false}, hub does not gate this row (consumables, throwables, …) even if
	 * usableColors exists for visuals. {@code null} ⇒ plugin treats the row as gated unless
	 * {@link #colorLockExcluded} opts it out — the hub should set {@code false} on every non-gated row.
	 */
	@SerializedName(value = "colorLockApplies", alternate = {
		"color_lock_applies",
		"trackedByColorLock",
		"tracked_by_color_lock",
		"colorLockTracked",
		"color_lock_tracked"
	})
	private Boolean colorLockApplies;

	/** When {@code true}, hub opts this row out of lock enforcement (same effect as {@code colorLockApplies: false}). */
	@SerializedName(value = "colorLockExcluded", alternate = {"color_lock_excluded"})
	private Boolean colorLockExcluded;

	/** Quest catalog keys — allow any team color while any key is in the player's in-progress quest set. */
	@SerializedName(value = "questColorLockKeys", alternate = {"quest_color_lock_keys"})
	private List<String> questColorLockKeys;

	private transient volatile List<String> normalizedUsableColors;
	private transient volatile List<String> normalizedQuestColorLockKeys;

	public int getId()
	{
		return id;
	}

	public String getCategory()
	{
		return category == null ? "" : category;
	}

	public String getName()
	{
		return name == null ? "" : name;
	}

	public List<String> getUsableColors()
	{
		return usableColors == null ? Collections.emptyList() : usableColors;
	}

	public Boolean getColorLockApplies()
	{
		return colorLockApplies;
	}

	public Boolean getColorLockExcluded()
	{
		return colorLockExcluded;
	}

	public List<String> getQuestColorLockKeys()
	{
		return questColorLockKeys == null ? Collections.emptyList() : questColorLockKeys;
	}

	List<String> getNormalizedQuestColorLockKeys()
	{
		List<String> cached = normalizedQuestColorLockKeys;
		if (cached != null)
		{
			return cached;
		}
		List<String> raw = getQuestColorLockKeys();
		if (raw.isEmpty())
		{
			normalizedQuestColorLockKeys = Collections.emptyList();
			return normalizedQuestColorLockKeys;
		}
		LinkedHashSet<String> deduped = new LinkedHashSet<>();
		for (String k : raw)
		{
			if (k == null)
			{
				continue;
			}
			String t = k.trim().toLowerCase(java.util.Locale.ENGLISH);
			if (!t.isEmpty())
			{
				deduped.add(t);
			}
		}
		cached = Collections.unmodifiableList(new ArrayList<>(deduped));
		normalizedQuestColorLockKeys = cached;
		return cached;
	}

	public int getSchemaVersionNumber()
	{
		return schemaVersion == null ? -1 : schemaVersion.intValue();
	}

	List<String> getNormalizedUsableColors()
	{
		List<String> cached = normalizedUsableColors;
		if (cached != null)
		{
			return cached;
		}
		List<String> raw = getUsableColors();
		if (raw.isEmpty())
		{
			normalizedUsableColors = Collections.emptyList();
			return normalizedUsableColors;
		}
		LinkedHashSet<String> deduped = new LinkedHashSet<>();
		for (String c : raw)
		{
			if (c == null)
			{
				continue;
			}
			String t = c.trim();
			if (!t.isEmpty())
			{
				deduped.add(t);
			}
		}
		cached = Collections.unmodifiableList(new ArrayList<>(deduped));
		normalizedUsableColors = cached;
		return cached;
	}
}

package com.osrscolorlock.colorlock;

import java.awt.Color;
import java.util.Locale;

/** Maps manifest palette strings to UI colors for dots / swatches. */
final class ColorLockPalette
{
	private ColorLockPalette()
	{
	}

	static Color toUiColor(String paletteKey)
	{
		if (paletteKey == null)
		{
			return new Color(140, 140, 150);
		}
		switch (paletteKey.trim().toLowerCase(Locale.ENGLISH))
		{
			case "red":
				return new Color(220, 72, 72);
			case "yellow":
				return new Color(230, 200, 70);
			case "green":
				return new Color(72, 170, 92);
			case "blue":
				return new Color(72, 128, 230);
			case "purple":
			case "violet":
				return new Color(160, 96, 210);
			case "brown":
				return new Color(150, 105, 72);
			case "black":
				return new Color(76, 80, 90);
			case "white":
				return new Color(235, 235, 240);
			case "orange":
				return new Color(230, 140, 64);
			case "pink":
				return new Color(230, 130, 168);
			default:
				return new Color(140, 140, 150);
		}
	}

	/** Short tag shown inside palette nodes (R, BL=black, Br=brown, …). */
	static String abbreviation(String paletteKeyRaw)
	{
		if (paletteKeyRaw == null)
		{
			return "?";
		}
		switch (paletteKeyRaw.trim().toLowerCase(Locale.ENGLISH))
		{
			case "red":
				return "R";
			case "yellow":
				return "Y";
			case "green":
				return "G";
			case "blue":
				return "B";
			case "purple":
			case "violet":
				return "P";
			case "brown":
				return "Br";
			case "black":
				return "BL";
			case "white":
				return "W";
			case "orange":
				return "O";
			case "pink":
				return "Pi";
			default:
				return "?";
		}
	}
}

package com.osrscolorlock.colorlock;

import com.google.gson.Gson;
