import static io.hydrox.contextualcursor.ContextualCursor.GENERIC_CURSOR_STANDALONE;
import java.awt.Dimension;
import java.awt.Graphics2D;
import java.awt.image.BufferedImage;
import javax.inject.Inject;
import net.runelite.api.Client;
import net.runelite.api.Point;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;

public class ContextualCursorDrawOverlay extends Overlay
{
	//The pointer sticks out to the left slightly, so this makes sure it's point to the correct spot
	private static final Point POINTER_OFFSET = new Point(-5, 0);
	//The centre of the circle (biased bottom right since it's an even size), for use with sprites
	private static final Point CENTRAL_POINT = new Point(16, 18);

	private final Client client;
	private final ContextualCursorPlugin plugin;
	private final SpriteContext spriteContext;

	private Point scaledCenterPoint = CENTRAL_POINT;
	private Point cursorOffset = POINTER_OFFSET;

	@Inject
	ContextualCursorDrawOverlay(Client client, ContextualCursorPlugin plugin, SpriteContext spriteContext)
	{
		setPosition(OverlayPosition.DYNAMIC);
		setLayer(OverlayLayer.ALWAYS_ON_TOP);
		setPriority(1f);
		this.client = client;
		this.plugin = plugin;
		this.spriteContext = spriteContext;
	}

	@Override
	public Dimension render(Graphics2D graphics)
	{
		Sprite sprite = plugin.getSpriteToDraw();

		if (sprite == null)
		{
			if (plugin.canDefaultCursorOverrideWithOverlay())
			{
				sprite = GENERIC_CURSOR_STANDALONE;
			}
			else
			{
				return null;
			}
		}

		BufferedImage image = sprite.getImage(spriteContext);
		if (image == null)
		{
			return null;
		}

		final Point mousePos = client.getMouseCanvasPosition();

		switch (sprite.getType())
		{
			case CONTEXTUAL:
				graphics.drawImage(BLANK_CURSOR.getImage(spriteContext), mousePos.getX() + cursorOffset.getX(), mousePos.getY() + cursorOffset.getY(), null);
				final int spriteX = cursorOffset.getX() + scaledCenterPoint.getX() - image.getWidth(null) / 2;
				final int spriteY = cursorOffset.getY() + scaledCenterPoint.getY() - image.getHeight(null) / 2;
				graphics.drawImage(image, mousePos.getX() + spriteX, mousePos.getY() + spriteY, null);
				break;
			case DEFAULT:
				graphics.drawImage(image, mousePos.getX(), mousePos.getY(), null);
				break;
		}

		return null;
	}

	public void updateScale()
	{
		scaledCenterPoint = scalePoint(CENTRAL_POINT, plugin.getCursorScale());
		cursorOffset = scalePoint(POINTER_OFFSET, plugin.getCursorScale());
	}

}

