@Singleton
public class SpriteContext
{
	@Inject
	@Getter
	private Client client;

	@Inject
	@Getter
	private SpriteManager spriteManager;

	@Inject
	@Getter
	private ItemManager itemManager;

	@Inject
	private ContextualCursorPlugin plugin;

