                break;
            case FREMENNIK:
                OutColor = config.FremennikColor();
                break;
            case KOUREND:
                OutColor = config.KourendColor();
                break;
            case WILDERNESS:
                OutColor = config.WildernessColor();
                break;
            case MORYTANIA:
                OutColor = config.MorytaniaColor();
                break;
            case TIRANNWN:
                OutColor = config.TirannwnColor();
                break;
            case DESERT:
                OutColor = config.DesertColor();
                break;
