                plugin.config.UserData.HiddenTasks.remove(taskData.GUID);
            }
            else
            {
                plugin.config.UserData.HiddenTasks.add(taskData.GUID);
                plugin.config.UserData.PlannedTasks.remove(taskData.GUID);
            }
            plugin.QueueRefresh();
        });
