                int CurrentOrder = 0;

                for (HashMap.Entry<UUID, TaskSortData> mapElement : plugin.config.UserData.PlannedTasks.entrySet())
                {
                    if (mapElement.getValue().SortPriority > CurrentOrder)
                    {
                        CurrentOrder = mapElement.getValue().SortPriority;
