{
    private static final String API_ENDPOINT = "https://api.streamable.com/upload";
    private static final MediaType BINARY = MediaType.parse("application/octet-stream");

    private final OkHttpClient http;
    private final KillClipsConfig cfg;
    private final Gson gson;

    // Listener called on successful upload: (description, url)
    private volatile BiConsumer<String, String> onClipUploaded;

    @Inject
    public StreamableUploader(OkHttpClient http, KillClipsConfig cfg, Gson gson)
    {
        // Override the shared RuneLite client's timeouts so uploads never hang forever.
        this.http = http.newBuilder()
            .connectTimeout(15, TimeUnit.SECONDS)
            .writeTimeout(5, TimeUnit.MINUTES)
            .readTimeout(60, TimeUnit.SECONDS)
            .callTimeout(10, TimeUnit.MINUTES)
            .build();
        this.cfg = cfg;
        this.gson = gson;
    }

    public void setOnClipUploaded(BiConsumer<String, String> listener)
    {
        this.onClipUploaded = listener;
    }

    public void upload(Path clip, String description)
    {
        if (!cfg.streamableEnabled())
        {
            return;
        }

        String user = cfg.streamableEmail();
        String pass = cfg.streamablePassword();
        if (user == null || user.isEmpty() || pass == null || pass.isEmpty())
        {
            log.warn("Streamable credentials not configured -- skipping upload");
            return;
        }

        if (!Files.exists(clip))
        {
            log.warn("Video file missing, cannot upload: {}", clip);
            return;
        }

        try
        {
            String name = clip.getFileName().toString();
            // Stream the file from disk instead of loading it into memory
            RequestBody filePart = RequestBody.create(BINARY, clip.toFile());
            MultipartBody payload = new MultipartBody.Builder()
                .setType(MultipartBody.FORM)
                .addFormDataPart("file", name, filePart)
                .build();

            Request req = new Request.Builder()
                .url(API_ENDPOINT)
                .header("Authorization", Credentials.basic(user, pass))
                .post(payload)
                .build();

            log.info("Starting Streamable upload: {}", name);

            final String desc = (description != null) ? description : name;

            http.newCall(req).enqueue(new Callback()
            {
                @Override
                public void onFailure(Call call, IOException ex)
                {
                    log.error("Streamable upload error for {}", name, ex);
                }

                @Override
                public void onResponse(Call call, Response resp) throws IOException
                {
                    try (resp)
                    {
                        String body = resp.body() != null ? resp.body().string() : "";
                        if (!resp.isSuccessful())
                        {
                            log.error("Streamable returned HTTP {} -- {}", resp.code(), body);
                            return;
                        }

                        JsonObject obj = gson.fromJson(body, JsonObject.class);
                        if (obj != null && obj.has("shortcode"))
                        {
                            String code = obj.get("shortcode").getAsString();
                            String url = "https://streamable.com/" + code;
                            log.info("Streamable upload finished: {}", url);

                            BiConsumer<String, String> listener = onClipUploaded;
                            if (listener != null)
                            {
                                listener.accept(desc, url);
                            }
                        }
                        else
                        {
                            log.warn("Unexpected Streamable response: {}", body);
                        }
                    }
                }
            });
        }
        catch (Exception ex)
        {
            log.error("Could not prepare Streamable upload: {}", clip, ex);
        }
    }
}

package com.killClips.api;

import com.google.gson.Gson;
import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import lombok.extern.slf4j.Slf4j;
import net.runelite.client.RuneLite;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

@Slf4j
@Singleton
public class ApiClient
{
    private static final DateTimeFormatter TS_FMT = DateTimeFormatter.ofPattern("yyyyMMdd_HHmmss_SSS");
    private static final DateTimeFormatter DISPLAY_DATE = DateTimeFormatter.ofPattern("MMM d");
    private static final Path CLIPS_JSON = RuneLite.RUNELITE_DIR.toPath().resolve("videos").resolve("clips.json");

    private final Gson gson;
    private final StreamableUploader streamable;

    @Inject
    public ApiClient(Gson gson, StreamableUploader streamable)
    {
        this.gson = gson;
        this.streamable = streamable;
    }

    public void sendEventToApi(String endpoint, String jsonBody, String label, byte[] videoBytes)
    {
        try
        {
            String kind = extractEventKind(endpoint);
            String ts = LocalDateTime.now().format(TS_FMT);
            String stem = kind + "_" + ts;

            JsonObject meta = toJsonObject(jsonBody);
            meta.addProperty("event_type", kind);
            meta.addProperty("saved_at", LocalDateTime.now().toString());

            String rawPlayer = meta.has("playername") ? meta.get("playername").getAsString() : "unknown";
            String player = sanitizePathSegment(rawPlayer);
            Path folder = RuneLite.RUNELITE_DIR.toPath().resolve("videos").resolve(player).resolve(kind);
            Files.createDirectories(folder);

            if (videoBytes != null && videoBytes.length > 0)
            {
                String ext = (videoBytes.length >= 8 && "ftyp".equals(new String(videoBytes, 4, 4, StandardCharsets.US_ASCII))) ? ".mp4" : ".avi";
                Path vidPath = folder.resolve(stem + ext);
                Files.write(vidPath, videoBytes);
                meta.addProperty("video_file", vidPath.toString());

                String clipDesc = buildClipDescription(meta);
                streamable.upload(vidPath, clipDesc);
            }

            appendToClipsJson(meta);
            log.debug("Persisted {} to clips.json", label);
        }
        catch (Exception ex)
        {
            log.error("Failed to persist {}", label, ex);
        }
    }

    // Keep only letters, digits, underscore, dash, and space — prevents any path-traversal
    // (.. or / or \) if a malformed player name ever reaches this code path.
    private static String sanitizePathSegment(String raw)
    {
        if (raw == null || raw.isEmpty())
        {
            return "unknown";
        }
        String cleaned = raw.replaceAll("[^a-zA-Z0-9 _-]", "_").trim();
        if (cleaned.isEmpty() || ".".equals(cleaned) || "..".equals(cleaned))
        {
            return "unknown";
        }
        if (cleaned.length() > 32)
        {
            cleaned = cleaned.substring(0, 32);
        }
        return cleaned;
    }

    private synchronized void appendToClipsJson(JsonObject entry)
    {
        try
        {
            Files.createDirectories(CLIPS_JSON.getParent());

            JsonArray clips;
            if (Files.exists(CLIPS_JSON))
            {
                String existing = Files.readString(CLIPS_JSON, StandardCharsets.UTF_8);
                JsonElement parsed = gson.fromJson(existing, JsonElement.class);
                clips = (parsed != null && parsed.isJsonArray()) ? parsed.getAsJsonArray() : new JsonArray();
            }
            else
            {
                clips = new JsonArray();
            }

            clips.add(entry);
            Files.writeString(CLIPS_JSON, gson.toJson(clips), StandardCharsets.UTF_8);
        }
        catch (Exception ex)
        {
            log.error("Failed to update clips.json", ex);
        }
    }

    private JsonObject toJsonObject(String raw)
    {
        try
        {
            JsonElement el = gson.fromJson(raw, JsonElement.class);
            if (el != null && el.isJsonObject())
            {
                return el.getAsJsonObject();
            }
        }
        catch (Exception ignored) {}

        JsonObject wrapper = new JsonObject();
        wrapper.addProperty("raw_payload", raw != null ? raw : "");
        return wrapper;
    }

    private String buildClipDescription(JsonObject meta)
    {
        String kind = meta.has("event_type") ? meta.get("event_type").getAsString() : "clip";
        String player = meta.has("playername") ? meta.get("playername").getAsString() : "unknown";
        String date = LocalDateTime.now().format(DISPLAY_DATE);

        switch (kind)
        {
            case "death":
                return player + " - death - " + date;
            case "kills":
                String victim = meta.has("killed_player") ? meta.get("killed_player").getAsString() : "someone";
                return victim + " - kill - " + date;
            default:
                return kind + " - " + date;
        }
    }

    private String extractEventKind(String ep)
    {
        if (ep == null || ep.isEmpty())
        {
            return "event";
        }
        int slash = ep.lastIndexOf('/');
        String segment = (slash >= 0) ? ep.substring(slash + 1) : ep;
        segment = segment.replaceAll("[^a-zA-Z0-9_\\-]", "_").toLowerCase();
        return segment.isEmpty() ? "event" : segment;
    }
}

package com.killClips;

import com.google.gson.Gson;
import com.google.inject.Provides;
import com.killClips.api.StreamableUploader;
import com.killClips.death.DeathTracker;
import com.killClips.playerdeath.CombatTracker;
import com.killClips.playerdeath.KillTracker;
import com.killClips.video.VideoRecorder;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.*;
import net.runelite.api.events.*;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.EventBus;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDependency;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.plugins.gpu.GpuPlugin;
import net.runelite.client.ui.ClientToolbar;
import net.runelite.client.ui.NavigationButton;

import javax.inject.Inject;
import java.awt.image.BufferedImage;

@Slf4j
@PluginDescriptor(
    name = "Kill Clips",
    description = "Automatically captures deaths and kills to local video files with Streamable upload",
    tags = {"kill", "clips", "deaths", "video", "streamable"}
)
@PluginDependency(GpuPlugin.class)
public class KillClipsPlugin extends Plugin
{
    @Inject private Client client;
    @Inject private KillClipsConfig config;
    @Inject private DeathTracker deathTracker;
    @Inject private KillTracker killTracker;
    @Inject private CombatTracker combatTracker;
    @Inject private VideoRecorder videoRecorder;
    @Inject private StreamableUploader streamableUploader;
    @Inject private ClientToolbar clientToolbar;
    @Inject private EventBus eventBus;
    @Inject private Gson gson;

    private NavigationButton navBtn;
    private KillClipsPanel sidePanel;
    private volatile boolean inSession = false;

    private EventBus.Subscriber gameStateSub;
    private EventBus.Subscriber interactingSub;
    private EventBus.Subscriber actorDeathSub;
    private EventBus.Subscriber gameTickSub;

    @Override
    protected void startUp() throws Exception
    {
        log.debug("Kill Clips starting");
        videoRecorder.startRecording();

        if (client.getGameState() == GameState.LOGGED_IN)
        {
            inSession = true;
        }

        sidePanel = new KillClipsPanel(gson);
        streamableUploader.setOnClipUploaded((desc, url) -> sidePanel.addClip(desc, url));

        BufferedImage icon = new BufferedImage(16, 16, BufferedImage.TYPE_INT_ARGB);
        java.awt.Graphics2D gfx = icon.createGraphics();
        gfx.setRenderingHint(java.awt.RenderingHints.KEY_ANTIALIASING, java.awt.RenderingHints.VALUE_ANTIALIAS_ON);
        gfx.setColor(new java.awt.Color(220, 40, 40));
        gfx.fillOval(2, 2, 12, 12);
        gfx.dispose();

        navBtn = NavigationButton.builder()
            .tooltip("Kill Clips")
            .icon(icon)
            .priority(10)
            .panel(sidePanel)
            .build();
        clientToolbar.addNavigation(navBtn);

        gameStateSub = eventBus.register(GameStateChanged.class, this::onGameStateChanged, 0);
        interactingSub = eventBus.register(InteractingChanged.class, this::onInteractingChanged, 0);
        actorDeathSub = eventBus.register(ActorDeath.class, this::onActorDeath, 0);
        gameTickSub = eventBus.register(GameTick.class, this::onGameTick, 0);
    }

    @Override
    protected void shutDown() throws Exception
    {
        log.debug("Kill Clips stopping");

        if (gameStateSub != null) eventBus.unregister(gameStateSub);
        if (interactingSub != null) eventBus.unregister(interactingSub);
        if (actorDeathSub != null) eventBus.unregister(actorDeathSub);
        if (gameTickSub != null) eventBus.unregister(gameTickSub);
        gameStateSub = interactingSub = actorDeathSub = gameTickSub = null;

        if (navBtn != null)
        {
            clientToolbar.removeNavigation(navBtn);
        }
        streamableUploader.setOnClipUploaded(null);
        try
        {
            videoRecorder.shutdown();
        }
        catch (Exception ex)
        {
            log.warn("VideoRecorder shutdown threw", ex);
        }
        inSession = false;
    }

    // All @Subscribe handlers below are wrapped in try/catch. An uncaught exception here
    // would detach the subscriber from the event bus for the rest of the session.

    private void onGameStateChanged(GameStateChanged evt)
    {
        try
        {
            GameState gs = evt.getGameState();
            if (gs == GameState.LOGGED_IN && !inSession)
            {
                inSession = true;
            }
            else if (gs == GameState.LOGIN_SCREEN && inSession)
            {
                inSession = false;
                combatTracker.reset();
            }
            else if (gs == GameState.HOPPING && inSession)
            {
                inSession = false;
                combatTracker.reset();
            }
        }
        catch (Exception ex)
        {
            log.warn("onGameStateChanged threw", ex);
        }
    }

    private void onInteractingChanged(InteractingChanged evt)
    {
        try
        {
            combatTracker.onInteractingChanged(evt.getSource(), evt.getTarget());
        }
        catch (Exception ex)
        {
            log.warn("onInteractingChanged threw", ex);
        }
    }

    private void onActorDeath(ActorDeath evt)
    {
        try
        {
            Actor who = evt.getActor();
            if (!(who instanceof Player))
            {
                return;
            }
            deathTracker.processActorDeath(who);
            killTracker.processActorDeath(who);
        }
        catch (Exception ex)
        {
            log.warn("onActorDeath threw", ex);
        }
    }

    private void onGameTick(GameTick tick)
    {
        try
        {
            videoRecorder.updateCaptureRateIfNeeded();
            combatTracker.onGameTick();
        }
        catch (Exception ex)
        {
            log.warn("onGameTick threw", ex);
        }
    }

    @Provides
    KillClipsConfig provideConfig(ConfigManager cfgMgr)
    {
        return cfgMgr.getConfig(KillClipsConfig.class);
    }
}

package com.killClips.death;

import com.google.gson.JsonObject;
import com.killClips.KillClipsConfig;
import com.killClips.api.ApiClient;
import com.killClips.video.VideoRecorder;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Actor;
import net.runelite.api.Client;
import net.runelite.api.Player;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.time.Instant;

// Records the local player's own deaths
@Slf4j
@Singleton
public class DeathTracker
{
    private static final int POST_DEATH_DELAY_MS = 5000;

    private final Client gameClient;
    private final ApiClient storage;
    private final KillClipsConfig cfg;
    private final VideoRecorder recorder;

    @Inject
    public DeathTracker(Client gameClient, ApiClient storage, KillClipsConfig cfg, VideoRecorder recorder)
    {
        this.gameClient = gameClient;
        this.storage = storage;
        this.cfg = cfg;
        this.recorder = recorder;
    }

    public void processActorDeath(Actor who)
    {
        Player me = gameClient.getLocalPlayer();
        if (me == null || who != me)
        {
            return;
        }

        log.debug("Local player died");
        captureAndStore();
    }

    private void captureAndStore()
    {
        recorder.captureEventVideo(
            (screenshotData, videoBytes) ->
            {
                String rsn = resolvePlayerName();

                JsonObject info = new JsonObject();
                info.addProperty("playername", rsn);
                info.addProperty("timestamp", Instant.now().toString());

                storage.sendEventToApi(
                    "/api/webhooks/death",
                    info.toString(),
                    "death",
                    videoBytes
                );
            },
            null,
            POST_DEATH_DELAY_MS
        );
    }

    private String resolvePlayerName()
    {
        Player me = gameClient.getLocalPlayer();
        if (me != null && me.getName() != null)
        {
            return me.getName();
        }
        return "unknown";
    }
}

package com.killClips;

