    @Getter @Setter private int lastMarkCount = 0;
    @Getter @Setter private boolean inventoryInitialized = false;

    public boolean isGoalAchieved()
    {
        return config.lapsRemaining() + config.marksRemaining() <= 0;
    }

    public boolean isRunning()
    {
        return currentCourse != null;
    }

    public void reset()
    {
        currentCourse = null;
        lastMarkCount = 0;
        inventoryInitialized = false;
    }
}

package com.mvpief;

import lombok.Getter;
import lombok.RequiredArgsConstructor;

@Getter
@RequiredArgsConstructor
public enum OverlayDisplayMode
{
    ALWAYS("Always Show"),
    ON_GOAL("Show when goal is not completed"),
    ON_RUNNING("Only show when running rooftops"),
    NEVER("Never show the overlay");

    private final String name;

    @Override
    public String toString()
    {
        return name;
    }
}

package com.mvpief;
import com.mvpief.state.SessionState;

import lombok.extern.slf4j.Slf4j;
import net.runelite.client.ui.overlay.OverlayPanel;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.components.LineComponent;

import javax.inject.Inject;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Graphics2D;

@Slf4j
public class DailyGoalOverlay extends OverlayPanel
{
    // region Setup

    private final DailyAgility plugin;

    @Inject
    private DailyAgilityConfig config;
    @Inject private SessionState sessionState;

    @Inject
    public DailyGoalOverlay(DailyAgility plugin)
    {
        this.plugin = plugin;
        setPosition(OverlayPosition.TOP_LEFT);
    }

    // endregion

    // region Render

    @Override
    public Dimension render(Graphics2D graphics)
    {
        panelComponent.getChildren().clear();
        if (!shouldRender()) return super.render(graphics);

        try
        {
            renderLapsLeft();
            renderMarksLeft();
            renderLastLapTime();
            String course = plugin.getCurrentCourse();
            renderAvgLapTime(course);
            renderETA(course);
        }
        catch (Exception e)
        {
            log.error("DailyGoalOverlay render error", e);
        }

        return super.render(graphics);
    }

    // endregion

    // region Render Helpers

    private void renderLapsLeft()
    {
        if (!config.showLapsLeft()) return;
        int laps = plugin.getLapsLeft();
        String value;
        Color color;

        if (laps < 0)
        {
            value = "+" + Math.abs(laps);
            color = Color.GREEN;
        }
        else
        {
            value = String.valueOf(laps);
            color = Color.WHITE;
        }

        panelComponent.getChildren().add(LineComponent.builder()
                .left("Laps left:")
                .right(value)
                .rightColor(color)
                .build());
    }

    private void renderMarksLeft()
    {
        if (!config.showMarksLeft()) return;
        int marks = plugin.getMarksLeft();
        String value;
        Color color;

        if (marks < 0)
        {
            value = "+" + Math.abs(marks);
            color = Color.GREEN;
        }
        else
        {
            value = String.valueOf(marks);
            color = Color.WHITE;
        }

        panelComponent.getChildren().add(LineComponent.builder()
                .left("Marks left:")
                .right(value)
                .rightColor(color)
                .build());
    }

    private void renderLastLapTime()
    {
        if (!config.showLapTime()) return;
        long duration = plugin.getLastLapDuration();
        if (duration == -1) return;

        panelComponent.getChildren().add(LineComponent.builder()
                .left("Last lap:")
                .right(formatSeconds(duration))
                .build());
    }

    private void renderAvgLapTime(String course)
    {
        if (course == null || !config.showAverageTime()) return;
        double avg = plugin.getAverageLapTime(course);
        if (avg <= 0) return;

        panelComponent.getChildren().add(LineComponent.builder()
                .left("Avg lap:")
                .right(formatSeconds((long) avg))
                .build());
    }

    private void renderETA(String course)
    {
        if (course == null || !config.showETA()) return;
        long eta = plugin.getEstimatedTimeRemainingMs();
        if (eta <= 0) return;

        panelComponent.getChildren().add(LineComponent.builder()
                .left("ETA:")
                .right(formatSeconds(eta))
                .build());
    }

    private boolean shouldRender()
    {
        OverlayDisplayMode mode = config.overlayDisplayMode();

        switch (mode) {
            case ALWAYS:
                return true;
            case ON_GOAL:
                return !sessionState.isGoalAchieved();
            case ON_RUNNING:
                return sessionState.isRunning();
            case NEVER:
                return false;
        }
        return false;

    }

    // endregion

    // region Utilities

    private String formatSeconds(long ms)
    {
        long totalSeconds = ms / 1000;
        long hours = totalSeconds / 3600;
        long minutes = (totalSeconds % 3600) / 60;
        long seconds = totalSeconds % 60;
        if (hours > 0) return hours + "h " + minutes + "m " + seconds + "s";
        if (minutes > 0) return minutes + "m " + seconds + "s";
        return seconds + "s";

    }

    // endregion
}

package com.mvpief;

import com.mvpief.state.SessionState;

import com.google.inject.Provides;
import lombok.Getter;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.ChatMessageType;
import net.runelite.api.Client;
import net.runelite.api.Item;
import net.runelite.api.ItemContainer;
import net.runelite.api.events.ChatMessage;
import net.runelite.api.events.ItemContainerChanged;
import net.runelite.api.gameval.InventoryID;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.Subscribe;
import net.runelite.client.events.ConfigChanged;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.ui.ClientToolbar;
import net.runelite.client.ui.NavigationButton;
import net.runelite.client.ui.overlay.OverlayManager;
import net.runelite.client.util.ImageUtil;
import net.runelite.api.events.MenuOptionClicked;

import javax.inject.Inject;
import java.awt.image.BufferedImage;
import java.util.Arrays;
import java.util.Set;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.time.LocalDate;

@Slf4j
@PluginDescriptor(name = "Daily Agility")
public class DailyAgility extends Plugin
{
	// region Constants

	private static final Pattern LAP_PATTERN = Pattern.compile("Your (.+) Rooftop lap count is: (\\d+)");
	private static final int MARK_OF_GRACE_ID = 11849;

	// endregion

	// region Injected

	@Inject private ConfigManager configManager;
	@Inject private Client client;
	@Inject private DailyAgilityConfig config;
	@Inject private OverlayManager overlayManager;
	@Inject private DailyGoalOverlay overlay;
	@Inject private ClientThread clientThread;
	@Inject private LapTimer lapTimer;
	@Inject private SessionState sessionState;
	@Inject private ClientToolbar clientToolbar;
	@Inject private DailyAgilityPanel panel;
	@Inject private LogStore logStore;

	// endregion

	// region State

	@Getter private String currentCourse = null;
	@Getter private int lastMarkCount = 0;
	private boolean inventoryInitialized = false;
    private boolean suppressedMarkPickups = false;

	// endregion

	// region Lifecycle

	@Override
	protected void startUp() throws Exception
	{
		resetDailyProgressIfNewDay();
		restoreLastKnownCourse();
		initInventory();
		initPanel();
		overlayManager.add(overlay);
	}

	@Override
	protected void shutDown() throws Exception
	{
		inventoryInitialized = false;
		lapTimer.reset();
		overlayManager.remove(overlay);
	}

	// endregion

	// region Getters

	public long getLastLapDuration()
	{
		return lapTimer.getLastLapDuration();
	}

	public double getAverageLapTime(String course)
	{
		return lapTimer.getAverageLapTime(course);
	}

	public int getLapsLeft()
	{
		return config.lapsRemaining();
	}

	public int getMarksLeft()
	{
		return config.marksRemaining();
	}


	public long getEstimatedTimeRemainingMs()
	{
		if (currentCourse == null) return -1;
		double avg = getAverageLapTime(currentCourse);
		if (avg < 0) return -1;
		int laps = config.lapsRemaining();
		if (laps <= 0) return 0;
		return (long) (avg * laps);
	}

	// endregion

	// region Internals

	private void resetDailyProgressIfNewDay()
	{
		String today = LocalDate.now().toString();
		String lastDate = config.lastSavedDate();

		if (!today.equals(lastDate))
		{
			configManager.setConfiguration(DailyAgilityConfig.GROUP, "lapsRemaining", config.dailyGoal());
			configManager.setConfiguration(DailyAgilityConfig.GROUP, "marksRemaining", config.marksGoal());
			configManager.setConfiguration(DailyAgilityConfig.GROUP, "lastSavedDate", today);
		}
	}

	private void initInventory()
	{
		clientThread.invokeLater(() ->
		{
			ItemContainer inventory = client.getItemContainer(InventoryID.INV);
			if (inventory == null)
			{
				return false; // retry next tick
			}

			lastMarkCount = Arrays.stream(inventory.getItems())
					.filter(item -> item.getId() == MARK_OF_GRACE_ID)
					.mapToInt(Item::getQuantity)
					.sum();
			inventoryInitialized = true;
			return true; // done
		});
	}

	private void initPanel()
	{
		final BufferedImage rawIcon = ImageUtil.loadImageResource(getClass(), "panel_logo.png");
		final BufferedImage icon = ImageUtil.resizeImage(rawIcon, 16, 16);

        // lower = further left in the sidebar
        NavigationButton navButton = NavigationButton.builder()
                .tooltip("Daily Agility")
                .icon(icon)
                .priority(6)           // lower = further left in the sidebar
                .panel(panel)
                .build();

		clientToolbar.addNavigation(navButton);
		panel.setOnDateSelected(date -> panel.setLogEntries(logStore.getEntries(null, date)));

		refreshPanel();
		refreshCalendarHighlights();
	}

	private void refreshPanel()
	{
		panel.setLogEntries(logStore.getEntries(null));
	}

	private void refreshCalendarHighlights()
	{
		Set<LocalDate> dates = logStore.getKnownDates().stream()
				.map(LocalDate::parse)
				.collect(java.util.stream.Collectors.toSet());
		panel.setDatesWithData(dates);
	}

	private void subtractLap()
	{
		int newLapCount = config.lapsRemaining() - 1;
		configManager.setConfiguration(DailyAgilityConfig.GROUP, "lapsRemaining", newLapCount);
		if (currentCourse != null) logStore.recordLap(currentCourse);
		refreshPanel();
		refreshCalendarHighlights();
	}

	private void markPickUp(int count)
	{
		int newCount = config.marksRemaining() - count;
		configManager.setConfiguration(DailyAgilityConfig.GROUP, "marksRemaining", newCount);
		if (currentCourse != null) logStore.recordMarks(currentCourse, count);
		refreshPanel();
	}

	private void restoreLastKnownCourse()
	{
		String saved = config.lastKnownCourse();
		if (saved != null && !saved.isEmpty())
		{
			currentCourse = saved;
			sessionState.setCurrentCourse(saved);
		}
	}

	// endregion

	// region Events

	@Subscribe
	public void onMenuOptionClicked(net.runelite.api.events.MenuOptionClicked event)
	{
		if (event.getItemId() == MARK_OF_GRACE_ID
				&& event.getMenuOption().equalsIgnoreCase("Drop"))
		{
			suppressedMarkPickups = true;
		}
	}

	@Subscribe
	public void onChatMessage(ChatMessage chatMessage)
	{
		if (chatMessage.getType() != ChatMessageType.GAMEMESSAGE) return;

		String clean = chatMessage.getMessage().replaceAll("<[^>]+>", "");
		Matcher matcher = LAP_PATTERN.matcher(clean);
		if (matcher.find())
		{
			String course = matcher.group(1);
			currentCourse = course;
			configManager.setConfiguration(DailyAgilityConfig.GROUP, "lastKnownCourse", course);
			subtractLap();
			lapTimer.recordLap(course);
			sessionState.setCurrentCourse(course);
		}
	}

	@Subscribe
	public void onConfigChanged(ConfigChanged event)
	{
		if (!event.getGroup().equals(DailyAgilityConfig.GROUP)) return;

		// TODO: make a button to set the current lapsRemaining to the current goal & make it increase by delta.
		// For now the lap counter just resets to the new dailGoal when changed.
		if (event.getKey().equals("dailyGoal"))
		{
			configManager.setConfiguration(DailyAgilityConfig.GROUP, "lapsRemaining", config.dailyGoal());
		}
		if (event.getKey().equals("marksGoal"))
		{
			configManager.setConfiguration(DailyAgilityConfig.GROUP, "marksRemaining", config.marksGoal());
		}
	}

	@Subscribe
	public void onItemContainerChanged(ItemContainerChanged event)
	{
		if (event.getContainerId() != InventoryID.INV) return;

		ItemContainer inventory = event.getItemContainer();
		int currentCount = Arrays.stream(inventory.getItems())
				.filter(item -> item.getId() == MARK_OF_GRACE_ID)
				.mapToInt(Item::getQuantity)
				.sum();

		if (!inventoryInitialized)
		{
			lastMarkCount = currentCount;
			inventoryInitialized = true;
			return;
		}

		if (currentCount > lastMarkCount)
		{
			if (suppressedMarkPickups)
			{
				suppressedMarkPickups = false;
			}
			else
			{
				int picked = currentCount - lastMarkCount;
				markPickUp(picked);
			}
		}

		lastMarkCount = currentCount;
	}

	// endregion

	// region Config

	@Provides
	DailyAgilityConfig provideConfig(ConfigManager configManager)
	{
		return configManager.getConfig(DailyAgilityConfig.class);
	}

	// endregion
}

package com.mvpief;

import lombok.Setter;
import net.runelite.client.ui.ColorScheme;
import net.runelite.client.ui.FontManager;
import net.runelite.client.ui.PluginPanel;

import javax.annotation.Nonnull;
import javax.swing.*;
import javax.swing.border.EmptyBorder;
import javax.swing.border.LineBorder;
import java.awt.*;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.YearMonth;
import java.time.format.TextStyle;
import java.util.HashSet;
import java.util.List;
import java.util.Locale;
import java.util.Set;
import java.util.function.Consumer;

public class DailyAgilityPanel extends PluginPanel
{
    // region Colors

    private static final Color COLOR_BG           = ColorScheme.DARK_GRAY_COLOR;
    private static final Color COLOR_CARD         = ColorScheme.DARKER_GRAY_COLOR;
    private static final Color COLOR_ACCENT       = new Color(200, 150, 0);   // gold
    private static final Color COLOR_TODAY_BORDER = new Color(200, 150, 0);
    private static final Color COLOR_SELECTED_BG  = new Color(80, 60, 0);
    private static final Color COLOR_HAS_DATA     = new Color(60, 100, 60);
    private static final Color COLOR_TEXT         = Color.WHITE;
    private static final Color COLOR_MUTED        = ColorScheme.LIGHT_GRAY_COLOR;
    private static final Color COLOR_HEADER_TEXT  = ColorScheme.MEDIUM_GRAY_COLOR;

    // endregion

    // region State

    private final JPanel      logContainer;
    private final JPanel      calendarGrid   = new JPanel();
    private final JLabel      monthYearLabel = new JLabel();

    private YearMonth         viewMonth      = YearMonth.now();
    private LocalDate         selectedDate   = null;   // null = all dates
    private Set<LocalDate>    datesWithData  = new HashSet<>();

    @Setter
    private Consumer<LocalDate> onDateSelected = date -> {};

    // endregion

    // region Constructor

    public DailyAgilityPanel()
    {
        super(false);
        setLayout(new BorderLayout(0, 8));
        setBackground(COLOR_BG);
        setBorder(new EmptyBorder(8, 8, 8, 8));

        add(buildNorth(), BorderLayout.NORTH);

        logContainer = new JPanel();
        logContainer.setLayout(new BoxLayout(logContainer, BoxLayout.Y_AXIS));
        logContainer.setBackground(COLOR_BG);

        JScrollPane scrollPane = new JScrollPane(logContainer);
        scrollPane.setBorder(null);
        scrollPane.setBackground(COLOR_BG);
        scrollPane.getViewport().setBackground(COLOR_BG);
        add(scrollPane, BorderLayout.CENTER);
    }

    // endregion

    // region Public API

    /**
     * Tell the calendar which dates have log data so it can highlight them.
     * Call this once after LogStore is ready, and again if new data comes in.
     */
    public void setDatesWithData(Set<LocalDate> dates)
    {
        this.datesWithData = dates;
        SwingUtilities.invokeLater(this::rebuildCalendarGrid);
    }

    public void setLogEntries(List<LogEntry> entries)
    {
        SwingUtilities.invokeLater(() ->
        {
            logContainer.removeAll();

            if (entries.isEmpty())
            {
                JLabel empty = new JLabel("No data for this selection.");
                empty.setForeground(COLOR_MUTED);
                empty.setFont(FontManager.getRunescapeSmallFont());
                empty.setBorder(new EmptyBorder(4, 0, 0, 0));
                logContainer.add(empty);
            }
            else
            {
                for (LogEntry entry : entries)
                {
                    logContainer.add(buildRow(entry));
                    logContainer.add(Box.createVerticalStrut(4));
                }
            }

            logContainer.revalidate();
            logContainer.repaint();
        });
    }

    // endregion

    // region Header + Title

    private JPanel buildNorth()
    {
        JPanel north = new JPanel();
        north.setLayout(new BoxLayout(north, BoxLayout.Y_AXIS));
        north.setBackground(COLOR_BG);

        // Title
        JLabel title = new JLabel("Daily Agility Log");
        title.setForeground(COLOR_TEXT);
        title.setFont(FontManager.getRunescapeBoldFont());
        title.setAlignmentX(Component.LEFT_ALIGNMENT);
        north.add(title);

        north.add(Box.createVerticalStrut(8));

        // Calendar card
        JPanel calendarCard = new JPanel(new BorderLayout(0, 4));
        calendarCard.setBackground(COLOR_CARD);
        calendarCard.setBorder(new EmptyBorder(8, 8, 8, 8));
        calendarCard.setAlignmentX(Component.LEFT_ALIGNMENT);

        calendarCard.add(buildMonthNav(), BorderLayout.NORTH);
        calendarCard.add(buildDayHeaders(), BorderLayout.CENTER);

        calendarGrid.setBackground(COLOR_CARD);
        calendarCard.add(calendarGrid, BorderLayout.SOUTH);

        north.add(calendarCard);
        north.add(Box.createVerticalStrut(4));

        // "Show all" button beneath the calendar
        JButton allButton = buildAllButton();
        allButton.setAlignmentX(Component.LEFT_ALIGNMENT);
        north.add(allButton);

        north.add(Box.createVerticalStrut(6));

        // Separator
        JSeparator sep = new JSeparator();
        sep.setForeground(ColorScheme.MEDIUM_GRAY_COLOR);
        sep.setAlignmentX(Component.LEFT_ALIGNMENT);
        sep.setMaximumSize(new Dimension(Integer.MAX_VALUE, 1));
        north.add(sep);

        rebuildCalendarGrid();

        return north;
    }

    // endregion

    // region Month navigation

    private JPanel buildMonthNav()
    {
        JPanel nav = new JPanel(new BorderLayout());
        nav.setBackground(COLOR_CARD);

        JButton prev = buildNavArrow("‹");
        prev.addActionListener(e ->
        {
            viewMonth = viewMonth.minusMonths(1);
            rebuildCalendarGrid();
        });

        JButton next = buildNavArrow("›");
        next.addActionListener(e ->
        {
            // Don't navigate into the future
            if (viewMonth.isBefore(YearMonth.now()))
            {
                viewMonth = viewMonth.plusMonths(1);
                rebuildCalendarGrid();
            }
        });

        monthYearLabel.setForeground(COLOR_TEXT);
        monthYearLabel.setFont(FontManager.getRunescapeSmallFont());
        monthYearLabel.setHorizontalAlignment(SwingConstants.CENTER);

        nav.add(prev, BorderLayout.WEST);
        nav.add(monthYearLabel, BorderLayout.CENTER);
        nav.add(next, BorderLayout.EAST);

        return nav;
    }

    private JButton buildNavArrow(String symbol)
    {
        JButton btn = new JButton(symbol);
        btn.setForeground(COLOR_MUTED);
        btn.setBackground(COLOR_CARD);
        btn.setBorder(new EmptyBorder(2, 6, 2, 6));
        btn.setFocusPainted(false);
        btn.setBorderPainted(false);
        btn.setContentAreaFilled(false);
        btn.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        btn.setFont(btn.getFont().deriveFont(16f));
        return btn;
    }

    // endregion

    // region Calendar grid

    /**
     * Day-of-week column headers: Mo Tu We Th Fr Sa Su
     */
    private JPanel buildDayHeaders()
    {
        JPanel headers = new JPanel(new GridLayout(1, 7, 2, 0));
        headers.setBackground(COLOR_CARD);
        headers.setBorder(new EmptyBorder(4, 0, 2, 0));

        // Start week on Monday to match EU convention
        for (DayOfWeek dow : DayOfWeek.values())
        {
            JLabel lbl = new JLabel(
                    dow.getDisplayName(TextStyle.SHORT, Locale.getDefault()).substring(0, 2),
                    SwingConstants.CENTER
            );
            lbl.setForeground(COLOR_HEADER_TEXT);
            lbl.setFont(FontManager.getRunescapeSmallFont());
            headers.add(lbl);
        }

        return headers;
    }

    private void rebuildCalendarGrid()
    {
        calendarGrid.removeAll();

        // 6 rows max, 7 columns
        calendarGrid.setLayout(new GridLayout(0, 7, 2, 2));

        monthYearLabel.setText(
                viewMonth.getMonth().getDisplayName(TextStyle.FULL, Locale.getDefault())
                        + " " + viewMonth.getYear()
        );

        LocalDate firstOfMonth = viewMonth.atDay(1);
        LocalDate today        = LocalDate.now();

        // Monday = 1, so offset = dayOfWeek - 1
        int leadingBlanks = firstOfMonth.getDayOfWeek().getValue() - 1;

        for (int i = 0; i < leadingBlanks; i++)
        {
            calendarGrid.add(emptyCell());
        }

        for (int day = 1; day <= viewMonth.lengthOfMonth(); day++)
        {
            LocalDate date = viewMonth.atDay(day);
            boolean isToday    = date.equals(today);
            boolean isSelected = date.equals(selectedDate);
            boolean hasData    = datesWithData.contains(date);
            boolean isFuture   = date.isAfter(today);

            calendarGrid.add(buildDayCell(date, isToday, isSelected, hasData, isFuture));
        }

        calendarGrid.revalidate();
        calendarGrid.repaint();
    }

    private JPanel buildDayCell(LocalDate date, boolean isToday, boolean isSelected,
                                boolean hasData, boolean isFuture)
    {
        JPanel cell = new JPanel(new BorderLayout());
        cell.setPreferredSize(new Dimension(28, 24));

        if (isSelected)
        {
            cell.setBackground(COLOR_SELECTED_BG);
            cell.setBorder(new LineBorder(COLOR_ACCENT, 1));
        }
        else if (isToday)
        {
            cell.setBackground(COLOR_CARD);
            cell.setBorder(new LineBorder(COLOR_TODAY_BORDER, 1));
        }
        else if (hasData)
        {
            cell.setBackground(COLOR_HAS_DATA);
            cell.setBorder(new EmptyBorder(1, 1, 1, 1));
        }
        else
        {
            cell.setBackground(COLOR_CARD);
            cell.setBorder(new EmptyBorder(1, 1, 1, 1));
        }

        JLabel lbl = new JLabel(String.valueOf(date.getDayOfMonth()), SwingConstants.CENTER);
        lbl.setFont(FontManager.getRunescapeSmallFont());
        lbl.setForeground(isFuture ? COLOR_HEADER_TEXT : COLOR_TEXT);
        cell.add(lbl, BorderLayout.CENTER);

        if (!isFuture)
        {
            cell.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
            cell.addMouseListener(new java.awt.event.MouseAdapter()
            {
                @Override
                public void mouseClicked(java.awt.event.MouseEvent e)
                {
                    selectedDate = date;
                    rebuildCalendarGrid();
                    onDateSelected.accept(date);
                }

                @Override
                public void mouseEntered(java.awt.event.MouseEvent e)
                {
                    if (!date.equals(selectedDate))
                    {
                        cell.setBackground(ColorScheme.MEDIUM_GRAY_COLOR);
                    }
                }

                @Override
                public void mouseExited(java.awt.event.MouseEvent e)
                {
                    if (!date.equals(selectedDate))
                    {
                        cell.setBackground(hasData ? COLOR_HAS_DATA : COLOR_CARD);
                    }
                }
            });
        }

        return cell;
    }

    private JPanel emptyCell()
    {
        JPanel cell = new JPanel();
        cell.setBackground(COLOR_CARD);
        cell.setPreferredSize(new Dimension(28, 24));
        return cell;
    }

    // endregion

    // region All button

    private JButton buildAllButton()
    {
        JButton btn = new JButton("Show all dates");
        btn.setFont(FontManager.getRunescapeSmallFont());
        btn.setForeground(COLOR_TEXT);
        btn.setBackground(ColorScheme.MEDIUM_GRAY_COLOR);
        btn.setBorder(new EmptyBorder(4, 8, 4, 8));
        btn.setFocusPainted(false);
