	private void addSection(JPanel parent, JPanel section)
	{
		section.setAlignmentX(Component.LEFT_ALIGNMENT);
		if (parent.getComponentCount() > 0)
		{
			parent.add(Box.createVerticalStrut(8));
		}
		parent.add(section);
	}

