	/**
	 * Shows the note box for the given player, prefilled with any saved note.
	 * Highlights the header when a note already exists (e.g. a known rat).
	 */
	public void setOpponentNote(String name, String existingNote)
	{
		noteForName = name;
		noteArea.setText(existingNote != null ? existingNote : "");
		noteSaveButton.setEnabled(true);

		boolean hasNote = existingNote != null && !existingNote.trim().isEmpty();
		if (hasNote)
		{
			noteHeader.setText("\u26A0 Note on " + name);
			noteHeader.setForeground(new Color(255, 170, 0)); // amber warning
		}
		else
		{
			noteHeader.setText("Note on " + name);
			noteHeader.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
		}

		revalidate();
		repaint();
	}

	public void setOpponentLoading(String name)
	{
		setOpponentTitle(name);
		opponentStatus.setText("Looking up stats…");
		opponentStatus.setVisible(true);
		skillGrid.setVisible(false);
		minigameRow.setVisible(false);
		setOpponentNote(name, plugin.getPlayerNote(name));
		revalidate();
		repaint();
	}

	public void setOpponentError(String name)
	{
		setOpponentTitle(name);
		opponentStatus.setText("Lookup failed (unranked?)");
		opponentStatus.setVisible(true);
		skillGrid.setVisible(false);
		minigameRow.setVisible(false);
		setOpponentNote(name, plugin.getPlayerNote(name));
		revalidate();
		repaint();
	}

	private void loadOpponentSkullIcon()
	{
		// Use the same in-game Slayer skull sprite as the menu/sidebar icons
		spriteManager.getSpriteAsync(net.runelite.api.SpriteID.SKILL_SLAYER, 0, sprite ->
		{
			if (sprite == null)
			{
				return;
			}
			java.awt.image.BufferedImage scaled = ImageUtil.resizeImage(sprite, 16, 16);
			javax.swing.SwingUtilities.invokeLater(() ->
			{
				opponentSkullIcon = new javax.swing.ImageIcon(scaled);
				if (opponentTitle.getText() != null && !opponentTitle.getText().isEmpty())
				{
					opponentTitle.setIcon(opponentSkullIcon);
				}
			});
		});
	}

	/**
	 * Sets the opponent title text and shows the skull icon before it.
	 */
	private void setOpponentTitle(String text)
	{
		opponentTitle.setText(text);
		opponentTitle.setIcon(opponentSkullIcon); // null-safe; no icon until loaded
		opponentTitle.setIconTextGap(4);
	}

	public void setOpponent(OpponentStats stats)
	{
		setOpponentTitle(stats.name + "   ⚔ " + stats.combatLevel);
		opponentStatus.setVisible(false);

		skillGrid.removeAll();
		skillGrid.add(skillCell("Attack", stats.attack));
		skillGrid.add(skillCell("Strength", stats.strength));
		skillGrid.add(skillCell("Defence", stats.defence));
		skillGrid.add(skillCell("Hitpoints", stats.hitpoints));
		skillGrid.add(skillCell("Ranged", stats.ranged));
		skillGrid.add(skillCell("Magic", stats.magic));
		skillGrid.add(skillCell("Prayer", stats.prayer));
		skillGrid.setVisible(true);

		minigameRow.removeAll();
		minigameRow.add(minigameCell("BH Hunter", HiscoreSkill.BOUNTY_HUNTER_HUNTER, stats.bhHunter));
		minigameRow.add(minigameCell("BH Rogue", HiscoreSkill.BOUNTY_HUNTER_ROGUE, stats.bhRogue));
		minigameRow.add(minigameCell("LMS", HiscoreSkill.LAST_MAN_STANDING, stats.lms));
		minigameRow.setVisible(true);

		// Refresh the note section for THIS opponent (was showing the prior one)
		setOpponentNote(stats.name, plugin.getPlayerNote(stats.name));

		revalidate();
		repaint();
	}


	private JPanel skillCell(String skillName, int level)
	{
		JPanel cell = new JPanel(new BorderLayout(4, 0));
		cell.setBackground(ColorScheme.DARKER_GRAY_COLOR);
		cell.setToolTipText(skillName);

		JLabel iconLabel = new JLabel();
		ImageIcon icon = loadIcon(
			"/skill_icons_small/" + skillName.toLowerCase() + ".png",
			"/skill_icons/" + skillName.toLowerCase() + ".png");
		if (icon != null)
		{
			iconLabel.setIcon(icon);
		}
		else
		{
			iconLabel.setText(skillName.substring(0, 3));
			iconLabel.setFont(FontManager.getRunescapeSmallFont());
			iconLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
		}

		JLabel value = new JLabel(String.valueOf(level));
		value.setFont(VALUE_FONT);
		value.setForeground(Color.WHITE);

		cell.add(iconLabel, BorderLayout.WEST);
		cell.add(value, BorderLayout.CENTER);
		return cell;
	}

	/**
	 * Minigame cells use the game's own sprites via SpriteManager —
	 * the same way RuneLite's hiscore panel renders them.
	 */
	private JPanel minigameCell(String label, HiscoreSkill skill, int score)
	{
		JPanel cell = new JPanel(new BorderLayout(4, 0));
		cell.setBackground(ColorScheme.DARKER_GRAY_COLOR);
		cell.setToolTipText(label + (score < 0 ? " — unranked" : " score: " + score));

		final JLabel iconLabel = new JLabel();
		try
		{
			spriteManager.getSpriteAsync(skill.getSpriteId(), 0, sprite ->
			{
				if (sprite == null)
				{
					return;
				}
				final BufferedImage scaled = ImageUtil.resizeImage(
					ImageUtil.resizeCanvas(sprite, 25, 25), 20, 20);
				SwingUtilities.invokeLater(() ->
				{
					iconLabel.setText(null);
					iconLabel.setIcon(new ImageIcon(scaled));
					iconLabel.revalidate();
					iconLabel.repaint();
				});
			});
		}
		catch (Throwable t)
		{
			// fall through to text fallback below
		}

		// Text fallback shown until/unless the sprite arrives
		if (iconLabel.getIcon() == null)
		{
			iconLabel.setText(shortLabel(label));
			iconLabel.setFont(FontManager.getRunescapeSmallFont());
			iconLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
		}

		JLabel value = new JLabel(score < 0 ? "-" : String.valueOf(score));
		value.setFont(VALUE_FONT);
		value.setForeground(score < 0 ? UNRANKED_GRAY : Color.WHITE);

		cell.add(iconLabel, BorderLayout.WEST);
		cell.add(value, BorderLayout.CENTER);
		return cell;
	}

	private static String shortLabel(String label)
	{
		switch (label)
		{
			case "BH Hunter":
				return "BH-H";
			case "BH Rogue":
				return "BH-R";
			default:
				return label;
		}
	}

	private static ImageIcon loadIcon(String... paths)
	{
		for (String path : paths)
		{
			try
			{
				BufferedImage img = ImageUtil.loadImageResource(PkTrackerPanel.class, path);
				if (img != null)
				{
					return new ImageIcon(img);
				}
			}
			catch (Throwable ignored)
			{
				// resource not present at this path in this client version
			}
		}
		return null;
	}
}

package com.pktracker;

import java.awt.Color;
import java.awt.Dimension;
import java.awt.Font;
import java.awt.FontMetrics;
import java.awt.Graphics2D;
import java.awt.image.BufferedImage;
import java.util.HashMap;
import java.util.Map;
import net.runelite.client.ui.FontManager;
import net.runelite.client.hiscore.HiscoreSkill;
import net.runelite.client.game.SpriteManager;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.util.ImageUtil;

/**
 * Custom-drawn opponent overlay: a skill icon grid (like the side panel),
 * BH/LMS ranks, saved note, and live damage. Renders with Graphics2D so the
 * layout matches the panel's grid look. Fades in/out smoothly.
 */
public class PkOpponentOverlay extends Overlay
{
	private static final Color BG = new Color(40, 40, 40, 220);
	private static final Color BORDER = new Color(70, 70, 70);
	private static final Color TEXT = Color.WHITE;
	private static final Color GREEN = new Color(0, 200, 83);
	private static final Color RED = new Color(244, 67, 54);
	private static final Color AMBER = new Color(255, 170, 0);
	private static final Color LIGHT = new Color(170, 170, 170);

	private static final int PAD = 8;
	private static final int WIDTH = 150;
	private static final int ICON = 16;
	private static final int ROW_H = 20;

	// Order matches the side panel grid (3 columns)
	private static final String[] SKILLS = {
		"attack", "strength", "defence",
		"hitpoints", "ranged", "magic", "prayer"
	};

	private final PkTrackerPlugin plugin;
	private final PkTrackerConfig config;
	private final SpriteManager spriteManager;

	private final Map<String, BufferedImage> icons = new HashMap<>();
	private boolean iconsLoaded = false;

	// BH/LMS minigame icons (loaded async from game sprites)
	private BufferedImage bhIcon;
	private BufferedImage lmsIcon;
	private boolean minigameIconsRequested = false;

	// Fade state
	private double alpha = 0.0;
	private static final double FADE_STEP = 0.12;

	public PkOpponentOverlay(PkTrackerPlugin plugin, PkTrackerConfig config, SpriteManager spriteManager)
	{
		this.plugin = plugin;
		this.config = config;
		this.spriteManager = spriteManager;
		setPosition(OverlayPosition.TOP_LEFT);
	}

	private void requestMinigameIcons()
	{
		minigameIconsRequested = true;
		spriteManager.getSpriteAsync(HiscoreSkill.BOUNTY_HUNTER_HUNTER.getSpriteId(), 0, s ->
		{
			if (s != null)
			{
				bhIcon = ImageUtil.resizeImage(s, ICON, ICON);
			}
		});
		spriteManager.getSpriteAsync(HiscoreSkill.LAST_MAN_STANDING.getSpriteId(), 0, s ->
		{
			if (s != null)
			{
				lmsIcon = ImageUtil.resizeImage(s, ICON, ICON);
			}
		});
	}

	private void loadIcons()
	{
		for (String s : SKILLS)
		{
			BufferedImage img = ImageUtil.loadImageResource(getClass(),
				"/skill_icons_small/" + s + ".png");
			if (img == null)
			{
				img = ImageUtil.loadImageResource(getClass(), "/skill_icons/" + s + ".png");
			}
			if (img != null)
			{
				icons.put(s, ImageUtil.resizeImage(img, ICON, ICON));
			}
		}
		iconsLoaded = true;
	}

	@Override
	public Dimension render(Graphics2D g)
	{
		final boolean shouldShow = config.opponentOverlay() && plugin.hasActiveFight();

		// Fade toward target
		alpha += shouldShow ? FADE_STEP : -FADE_STEP;
		if (alpha <= 0)
		{
			alpha = 0;
			return null;
		}
		if (alpha > 1)
		{
			alpha = 1;
		}

		if (!iconsLoaded)
		{
			loadIcons();
		}

		final OpponentStats stats = plugin.getLastOpponentStats();
		final String name = stats != null ? stats.name : plugin.getCurrentOpponentName();
		final String note = plugin.getNoteFor(name);
		final boolean hasNote = note != null && !note.isEmpty();

		// Compute height
		int rows = 0;
		rows += 1;                       // title
		if (hasNote) rows += 1;          // note line
		if (stats != null) rows += 3;    // 7 skills in 3 cols = 3 rows
		if (stats != null) rows += 1;    // bh/lms row
		final int height = PAD * 2 + rows * ROW_H;

		java.awt.Composite old = g.getComposite();
		g.setComposite(java.awt.AlphaComposite.getInstance(
			java.awt.AlphaComposite.SRC_OVER, (float) alpha));

		// Background
		g.setColor(BG);
		g.fillRect(0, 0, WIDTH, height);
		g.setColor(BORDER);
		g.drawRect(0, 0, WIDTH - 1, height - 1);

		final Font font = FontManager.getRunescapeSmallFont();
		g.setFont(font);
		final FontMetrics fm = g.getFontMetrics();

		int y = PAD + ROW_H - 6;

		// Title: name + combat level (crossed-swords symbol, like the panel)
		g.setColor(TEXT);
		String title = name != null ? name : "Opponent";
		if (stats != null && stats.combatLevel > 0)
		{
			title = title + "  \u2694 " + stats.combatLevel;
		}
		g.drawString(title, PAD, y);
		y += ROW_H;

		// Note (amber, read-only)
		if (hasNote)
		{
			g.setColor(AMBER);
			String n = "\u26A0 " + note;
			if (fm.stringWidth(n) > WIDTH - PAD * 2)
			{
				// truncate to fit
				while (n.length() > 4 && fm.stringWidth(n + "…") > WIDTH - PAD * 2)
				{
					n = n.substring(0, n.length() - 1);
				}
				n = n + "…";
			}
			g.drawString(n, PAD, y);
			y += ROW_H;
		}

		// Skill grid (3 columns)
		if (stats != null)
		{
			int[] levels = {
				stats.attack, stats.strength, stats.defence,
				stats.hitpoints, stats.ranged, stats.magic, stats.prayer
			};
			final int colW = (WIDTH - PAD * 2) / 3;
			for (int i = 0; i < SKILLS.length; i++)
			{
				int col = i % 3;
				int rowY = y + (i / 3) * ROW_H;
				int x = PAD + col * colW;

				BufferedImage icon = icons.get(SKILLS[i]);
				if (icon != null)
				{
					g.drawImage(icon, x, rowY - ICON + 4, null);
				}
				g.setColor(TEXT);
				g.drawString(String.valueOf(levels[i]), x + ICON + 2, rowY);
			}
			y += 3 * ROW_H;

			// BH / LMS row — icons + numbers
			if (!minigameIconsRequested)
			{
				requestMinigameIcons();
			}
			int mx = PAD;
			if (stats.bhHunter >= 0)
			{
				if (bhIcon != null)
				{
					g.drawImage(bhIcon, mx, y - ICON + 4, null);
					mx += ICON + 2;
				}
				g.setColor(TEXT);
				g.drawString(String.valueOf(stats.bhHunter), mx, y);
				mx += fm.stringWidth(String.valueOf(stats.bhHunter)) + 10;
			}
			if (stats.lms >= 0)
			{
				if (lmsIcon != null)
				{
					g.drawImage(lmsIcon, mx, y - ICON + 4, null);
					mx += ICON + 2;
				}
				g.setColor(TEXT);
				g.drawString(String.valueOf(stats.lms), mx, y);
			}
			if (stats.bhHunter < 0 && stats.lms < 0)
			{
				g.setColor(LIGHT);
				g.drawString("Unranked", PAD, y);
			}
			y += ROW_H;
		}

		g.setComposite(old);
		return new Dimension(WIDTH, height);
	}
}

package com.pktracker;

import java.awt.Color;
import java.awt.Dimension;
import java.awt.Font;
import java.awt.FontMetrics;
import java.awt.Graphics2D;
import net.runelite.client.ui.FontManager;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayPosition;

/**
 * Custom-drawn session stats overlay: kills, deaths, K/D, streak, loot.
 * Styled to match the panel; always visible when enabled.
 */
public class PkSessionOverlay extends Overlay
{
	private static final Color BG = new Color(40, 40, 40, 220);
	private static final Color BORDER = new Color(70, 70, 70);
	private static final Color TEXT = Color.WHITE;
	private static final Color GREEN = new Color(0, 200, 83);
	private static final Color RED = new Color(244, 67, 54);
	private static final Color LIGHT = new Color(170, 170, 170);

	private static final int PAD = 8;
	private static final int WIDTH = 140;
	private static final int ROW_H = 18;

	private final PkTrackerPlugin plugin;
	private final PkTrackerConfig config;

	public PkSessionOverlay(PkTrackerPlugin plugin, PkTrackerConfig config)
	{
		this.plugin = plugin;
		this.config = config;
		setPosition(OverlayPosition.TOP_LEFT);
	}

	@Override
	public Dimension render(Graphics2D g)
	{
		if (!config.sessionOverlay())
		{
			return null;
		}

		final int kills = plugin.getSessionKills();
		final int deaths = plugin.getSessionDeaths();
		final String kd = deaths == 0
			? kills + ".00"
			: String.format("%.2f", (double) kills / deaths);

		final int rows = 6; // title + 5 stats
		final int height = PAD * 2 + rows * ROW_H;

		g.setColor(BG);
		g.fillRect(0, 0, WIDTH, height);
		g.setColor(BORDER);
		g.drawRect(0, 0, WIDTH - 1, height - 1);

		final Font font = FontManager.getRunescapeSmallFont();
		g.setFont(font);
		final FontMetrics fm = g.getFontMetrics();

		int y = PAD + ROW_H - 5;

		g.setColor(TEXT);
		g.drawString("PK Session", PAD, y);
		y += ROW_H;

		drawRow(g, fm, "Kills", String.valueOf(kills), GREEN, y); y += ROW_H;
		drawRow(g, fm, "Deaths", String.valueOf(deaths), RED, y); y += ROW_H;
		drawRow(g, fm, "K/D", kd, TEXT, y); y += ROW_H;
		drawRow(g, fm, "Streak", String.valueOf(plugin.getKillStreak()), TEXT, y); y += ROW_H;
		drawRow(g, fm, "Loot", formatValue(plugin.getSessionLootValue()), GREEN, y);

		return new Dimension(WIDTH, height);
	}

	private void drawRow(Graphics2D g, FontMetrics fm, String label, String value, Color valueColor, int y)
	{
		g.setColor(LIGHT);
		g.drawString(label, PAD, y);
		g.setColor(valueColor);
		int vx = WIDTH - PAD - fm.stringWidth(value);
		g.drawString(value, vx, y);
	}

	private static String formatValue(long value)
	{
		if (value >= 1_000_000)
		{
			return String.format("%.1fM", value / 1_000_000.0);
		}
		if (value >= 1_000)
		{
			return String.format("%.1fK", value / 1_000.0);
		}
		return String.valueOf(value);
	}
}

