	{
		NPC npc = event.getNpc();
		if (npc == null)
		{
			return;
		}

		handleLoot(cleanName(npc.getName()), event.getItems());
	}

	@Subscribe
	public void onServerNpcLoot(ServerNpcLoot event)
	{
		NPCComposition composition = event.getComposition();
		if (composition == null)
		{
