package com.github.m0bilebtw.sound;

import org.junit.Test;

import javax.sound.sampled.AudioFormat;
import javax.sound.sampled.AudioInputStream;
import javax.sound.sampled.AudioSystem;
import javax.sound.sampled.UnsupportedAudioFileException;
import java.io.File;
import java.io.IOException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import java.util.stream.Collectors;

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertFalse;
import static org.junit.Assert.assertTrue;

public class SoundTest {

    @Test
    public void valuesPopulated() {
        for (Sound sound : Sound.values()) {
            String message = "Sound " + sound.name() + " should have a non-blank resource name";
            assertFalse(message, sound.getResourceName().isBlank());
        }
    }

    @Test
    public void noDuplicateValues() {
        Set<String> uniqueResourceNames = Arrays.stream(Sound.values())
                .map(Sound::getResourceName)
                .collect(Collectors.toSet());

        assertEquals(Sound.values().length, uniqueResourceNames.size());
    }

    /**
     * Bash snippets to also help in identifying and automatically fixing such files.
     * It's better to run these in the sounds folder in .runelite rather than the sounds branch of the repo,
     * because then you automatically ignore any previous revisions of a sound.
     * <p>
     * Identify sounds that will cut off:
     * <p>
     * {@code for f in *.wav; do duration=$(ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "$f"); echo "$f $duration"; done}
     * <p>
     * Create new sounds that are padded to prevent cut off where needed:
     * <p>
     * {@code for f in *.wav; do duration=$(ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "$f"); if (( $(echo "$duration >= 1.491 && $duration < 2" | bc -l) )); then padding=$(echo "2 - $duration" | bc -l); ffmpeg -i "$f" -af "apad=pad_dur=0$padding" -y "${f%.wav}_PADDED.wav"; fi; done}
     */
    @Test
    public void soundsAvoidDurationRangeThatPipeWireCutsOff() throws UnsupportedAudioFileException, IOException {
        // bounds found by manually testing to 3 d.p. - both 1.492 and 1.999 (and all in-between) get cut off
        final double lowerBoundExc = 1.491;
        final double upperBoundExc = 2.0;

        Set<Sound> cutOffSounds = new HashSet<>();
        for (Sound sound : Sound.values()) {
            final double duration = getDurationInSeconds(sound);
            if (duration > lowerBoundExc && duration < upperBoundExc) {
                cutOffSounds.add(sound);
            }
        }

        assertTrue(
                cutOffSounds.size() + " sounds will get cut off on PipeWire\n" +
                cutOffSounds.stream().map(s -> s.name() + ": " + s.getResourceName()).collect(Collectors.joining("\n")) + "\n",
                cutOffSounds.isEmpty()
        );
    }

    private double getDurationInSeconds(Sound sound) throws UnsupportedAudioFileException, IOException {
        File file = SoundFileManager.getSoundFile(sound);
        AudioInputStream audioInputStream = AudioSystem.getAudioInputStream(file);
        AudioFormat format = audioInputStream.getFormat();
        long frames = audioInputStream.getFrameLength();
        return (double) frames / format.getFrameRate();
    }
}

package com.zmihelper;

import java.util.function.ToIntFunction;
import net.runelite.api.Client;
import net.runelite.api.Skill;
import net.runelite.api.annotations.Varbit;
import net.runelite.api.gameval.VarbitID;
import net.runelite.api.gameval.VarPlayerID;

enum EssPouch
{
	SMALL(VarbitID.SMALL_ESSENCE_POUCH, null, new int[]{}, 3),
	MEDIUM(VarbitID.MEDIUM_ESSENCE_POUCH, client -> client.getVarpValue(VarPlayerID.RCU_POUCH_DEGRADATION_MED), new int[]{
		800, 0,
		400, 3,
	}, 6),
	LARGE(VarbitID.LARGE_ESSENCE_POUCH, client -> client.getVarpValue(VarPlayerID.RCU_POUCH_DEGRADATION_LARGE), new int[]{
		1000, 0,
		800, 3,
		600, 5,
		400, 7,
	}, 9),
	GIANT(VarbitID.GIANT_ESSENCE_POUCH, client -> client.getVarpValue(VarPlayerID.RCU_POUCH_DEGRADATION_GIANT), new int[]{
		1200, 0,
		1000, 3,
		800, 5,
		600, 6,
		400, 7,
		300, 8,
		200, 9,
	}, 12),
	COLOSSAL(VarbitID.COLOSSAL_ESSENCE_POUCH, client -> client.getVarbitValue(VarbitID.RCU_POUCH_DEGRADATION_COLOSSAL), new int[]{
		1020, 0,
		1015, 5,
		995, 10,
		950, 15,
		870, 20,
		745, 25,
		565, 30,
		320, 35,
	}, 40)
	{
		@Override
		int scaleLimit(Client client, int limit)
		{
			int rc = client.getRealSkillLevel(Skill.RUNECRAFT);
			int scaledMax;
			if (rc >= 85)
			{
				scaledMax = 40;
			}
			else if (rc >= 75)
			{
				scaledMax = 27;
			}
			else if (rc >= 50)
			{
				scaledMax = 16;
			}
			else
			{
				scaledMax = 8;
			}

			return Math.max(1, (limit * scaledMax) / 40);
		}
	};

	@Varbit
	private final int amountVarb;
	final ToIntFunction<Client> getDegradation;
	private final int[] degradationLevels;
	private final int maxFill;

	int scaleLimit(Client client, int limit)
	{
		return limit;
	}

	int maxAmount(Client client)
	{
		int deg = getDegradation(client);
		int limit = this.maxFill;
		for (int i = 0; i < degradationLevels.length; i += 2)
		{
			if (deg >= degradationLevels[i])
			{
				limit = degradationLevels[i + 1];
				break;
			}
		}

		if (limit > 0)
		{
			limit = this.scaleLimit(client, limit);
		}

		return limit;
	}

	int nextDegradationBreakpoint(Client client)
	{
		int deg = this.getDegradation.applyAsInt(client);
		for (int i = degradationLevels.length - 2; i >= 0; i -= 2)
		{
			if (deg < degradationLevels[i])
			{
				return degradationLevels[i];
			}
		}
		return deg;
	}

	int getDegradation(Client client)
	{
		if (this.getDegradation == null)
		{
			return 0;
		}

		return this.getDegradation.applyAsInt(client);
	}

	int getAmount(Client client)
	{
		return client.getVarbitValue(amountVarb);
	}

	EssPouch(int amountVarb, ToIntFunction<Client> getDegradation, int[] degradationLevels, int maxFill)
	{
		this.amountVarb = amountVarb;
		this.getDegradation = getDegradation;
		this.degradationLevels = degradationLevels;
		this.maxFill = maxFill;
	}
}

package com.zmihelper;

import java.awt.Color;
import java.awt.Dimension;
import java.awt.Graphics2D;
import javax.inject.Inject;
import net.runelite.api.Client;
import net.runelite.api.gameval.VarbitID;
import net.runelite.client.ui.overlay.OverlayPanel;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.components.LineComponent;

class ZmiHelperRunEnergyReminder extends OverlayPanel
{
	private final Client client;
	private final ZmiHelperPlugin plugin;
	private final ZmiHelperConfig config;

	@Inject
	private ZmiHelperRunEnergyReminder(Client client, ZmiHelperPlugin plugin, ZmiHelperConfig config)
	{
		this.client = client;
		this.plugin = plugin;
		this.config = config;
	}

	@Override
	public Dimension render(Graphics2D graphics)
	{
		if (!plugin.runEnergyLow || !config.enableRunEnergyTextReminder())
		{
			return null;
		}

		if (config.runEnergyRequireAltar() && !plugin.isInUpperZmiArea())
		{
			return null;
		}

		panelComponent.getChildren().clear();

		int spellbook = client.getVarbitValue(VarbitID.SPELLBOOK);
		String spellName = spellbook == 2 ? "Spellbook Swap" : "Vile Vigour";
		String text = "Low run energy — " + spellName;
		Color color = ZmiHelperColors.getReminderColor(client, config.flashRunEnergyReminder());
		panelComponent.getChildren().add(LineComponent.builder()
			.left(text)
			.leftColor(color)
			.build());

		setPosition(OverlayPosition.ABOVE_CHATBOX_RIGHT);
		return panelComponent.render(graphics);
	}
}

package com.zmihelper;

import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Graphics2D;
import java.awt.Shape;
import java.awt.Stroke;
import javax.inject.Inject;
import net.runelite.api.Client;
import net.runelite.api.GameObject;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayUtil;

class ZmiHelperAltarOverlay extends Overlay
{
	private final Client client;
	private final ZmiHelperPlugin plugin;
	private final ZmiHelperConfig config;

	@Inject
	private ZmiHelperAltarOverlay(Client client, ZmiHelperPlugin plugin, ZmiHelperConfig config)
	{
		this.client = client;
		this.plugin = plugin;
		this.config = config;
		setPosition(OverlayPosition.DYNAMIC);
		setLayer(OverlayLayer.ABOVE_SCENE);
	}

	@Override
	public Dimension render(Graphics2D graphics)
	{
		if (!plugin.isInUpperZmiArea())
		{
			return null;
		}

		boolean shouldHighlight = false;

		if (config.prayerThreshold() > 0 && plugin.currentPrayer < config.prayerThreshold())
		{
			shouldHighlight = true;
		}

		if (!shouldHighlight && config.highlightAltarLowRunEnergy() && plugin.runEnergyLow)
		{
			shouldHighlight = true;
		}

		if (!shouldHighlight)
		{
			return null;
		}

		renderAltarHull(graphics, plugin.chaosAltar);

		return null;
	}

	private void renderAltarHull(Graphics2D graphics, GameObject altar)
	{
		Shape hull = altar.getConvexHull();
		if (hull == null)
		{
			return;
		}

		Color borderColor = config.prayerAltarHighlightColor();
		Color fillColor = new Color(borderColor.getRed(), borderColor.getGreen(), borderColor.getBlue(), 50);
		Stroke stroke = new BasicStroke(2);

		OverlayUtil.renderPolygon(graphics, hull, borderColor, fillColor, stroke);
	}
}

