    ),
    TARROMIN(
        ItemID.GRIMY_TARROMIN, ItemID.TARROMIN, ItemID.TARROMIN_POTION_UNF,
        "Tarromin", 11, 5.0
    ),
    HARRALANDER(
        ItemID.GRIMY_HARRALANDER, ItemID.HARRALANDER, ItemID.HARRALANDER_POTION_UNF,
        "Harralander", 20, 6.3
    ),
    RANARR(
        ItemID.GRIMY_RANARR_WEED, ItemID.RANARR_WEED, ItemID.RANARR_POTION_UNF,
        "Ranarr weed", 25, 7.5
    ),
    TOADFLAX(
        ItemID.GRIMY_TOADFLAX, ItemID.TOADFLAX, ItemID.TOADFLAX_POTION_UNF,
        "Toadflax", 30, 8.0
    ),
    IRIT(
        ItemID.GRIMY_IRIT_LEAF, ItemID.IRIT_LEAF, ItemID.IRIT_POTION_UNF,
        "Irit leaf", 40, 8.8
    ),
    AVANTOE(
        ItemID.GRIMY_AVANTOE, ItemID.AVANTOE, ItemID.AVANTOE_POTION_UNF,
        "Avantoe", 48, 10.0
    ),
    KWUARM(
        ItemID.GRIMY_KWUARM, ItemID.KWUARM, ItemID.KWUARM_POTION_UNF,
        "Kwuarm", 54, 11.3
    ),
    SNAPDRAGON(
        ItemID.GRIMY_SNAPDRAGON, ItemID.SNAPDRAGON, ItemID.SNAPDRAGON_POTION_UNF,
        "Snapdragon", 59, 11.8
    ),
    CADANTINE(
        ItemID.GRIMY_CADANTINE, ItemID.CADANTINE, ItemID.CADANTINE_POTION_UNF,
        "Cadantine", 65, 12.5
    ),
    LANTADYME(
        ItemID.GRIMY_LANTADYME, ItemID.LANTADYME, ItemID.LANTADYME_POTION_UNF,
        "Lantadyme", 67, 13.1
    ),
    DWARF_WEED(
        ItemID.GRIMY_DWARF_WEED, ItemID.DWARF_WEED, ItemID.DWARF_WEED_POTION_UNF,
        "Dwarf weed", 70, 13.8
    ),
    TORSTOL(
        ItemID.GRIMY_TORSTOL, ItemID.TORSTOL, ItemID.TORSTOL_POTION_UNF,
        "Torstol", 75, 15.0
    );

    private final int grimyItemId;
    private final int cleanItemId;
    private final int unfPotionId;
    private final String displayName;
    private final int cleanLevel;
    private final double cleanXp;

    private static final Map<Integer, HerbData> BY_GRIMY_ID = new HashMap<>();
    private static final Map<Integer, HerbData> BY_CLEAN_ID = new HashMap<>();
    private static final Map<Integer, HerbData> BY_UNF_ID = new HashMap<>();

    static
    {
        for (HerbData herb : values())
        {
            BY_GRIMY_ID.put(herb.grimyItemId, herb);
            BY_CLEAN_ID.put(herb.cleanItemId, herb);
            BY_UNF_ID.put(herb.unfPotionId, herb);
        }
    }

    public static HerbData fromGrimyId(int itemId)
    {
        return BY_GRIMY_ID.get(itemId);
    }

    public static HerbData fromCleanId(int itemId)
    {
        return BY_CLEAN_ID.get(itemId);
    }

    public static HerbData fromUnfId(int itemId)
    {
        return BY_UNF_ID.get(itemId);
    }

    public static HerbData fromAnyId(int itemId)
    {
        HerbData herb = fromGrimyId(itemId);
        if (herb != null) return herb;
        herb = fromCleanId(itemId);
        if (herb != null) return herb;
        return fromUnfId(itemId);
    }

    public boolean isGrimy(int itemId)
    {
        return itemId == grimyItemId;
    }

    public boolean isClean(int itemId)
    {
        return itemId == cleanItemId;
    }

    public boolean isUnf(int itemId)
    {
        return itemId == unfPotionId;
    }
}

package com.lootingbagherblore.data;

import lombok.Getter;
import net.runelite.api.Item;
import net.runelite.api.ItemContainer;
import net.runelite.api.ItemID;

import java.util.*;

/**
 * Tracks secondary ingredients and vials of water across
 * looting bag and inventory, and calculates what's missing.
 */
public class SupplyTracker
{
    @Getter
    private int vialsInBag = 0;
    @Getter
    private int vialsInInventory = 0;

    // Secondary item counts: itemId -> quantity (bag + inventory combined)
    @Getter
    private final Map<Integer, Integer> secondariesInBag = new LinkedHashMap<>();
    @Getter
    private final Map<Integer, Integer> secondariesInInventory = new LinkedHashMap<>();

    // Bird's nest variants (all crushable into crushed nest 1:1 for Saradomin brew)
    private static final Set<Integer> BIRD_NEST_IDS = new HashSet<>(Arrays.asList(
        ItemID.BIRD_NEST,        // 5070
        ItemID.BIRD_NEST_5071,
        ItemID.BIRD_NEST_5072,
        ItemID.BIRD_NEST_5073,
        ItemID.BIRD_NEST_5074,
        ItemID.BIRD_NEST_5075,
        ItemID.BIRD_NEST_7413,
        ItemID.BIRD_NEST_13653,
        ItemID.BIRD_NEST_22798
    ));

    public static boolean isBirdNest(int itemId)
    {
        return BIRD_NEST_IDS.contains(itemId);
    }

    public void updateFromBag(ItemContainer container)
    {
        vialsInBag = 0;
        secondariesInBag.clear();
        if (container == null) return;
        scanContainer(container, true);
    }

    public void updateFromInventory(ItemContainer container)
    {
        vialsInInventory = 0;
        secondariesInInventory.clear();
        if (container == null) return;
        scanContainer(container, false);
    }

    /**
     * Update bag supplies from a flat itemId->quantity map, e.g. parsed
     * from a widget. Handles vials and secondaries.
     */
    public void updateFromBagItemCounts(Map<Integer, Integer> itemCounts)
    {
        vialsInBag = 0;
        secondariesInBag.clear();
        if (itemCounts == null) return;

        for (Map.Entry<Integer, Integer> entry : itemCounts.entrySet())
        {
            int itemId = entry.getKey();
            int qty = entry.getValue();

            if (itemId == ItemID.VIAL_OF_WATER)
            {
                vialsInBag += qty;
            }
            else if (isBirdNest(itemId))
            {
                // Crushable 1:1 into crushed nest — count toward the same supply
                secondariesInBag.merge(ItemID.CRUSHED_NEST, qty, Integer::sum);
            }
            else if (isSecondaryIngredient(itemId))
            {
                secondariesInBag.merge(itemId, qty, Integer::sum);
            }
        }
    }

    private void scanContainer(ItemContainer container, boolean isBag)
    {
        for (Item item : container.getItems())
        {
            if (item.getId() == -1) continue;

            if (item.getId() == ItemID.VIAL_OF_WATER)
            {
                if (isBag)
                    vialsInBag += item.getQuantity();
                else
                    vialsInInventory += item.getQuantity();
                continue;
            }

            if (isBirdNest(item.getId()))
            {
                // Crushable 1:1 into crushed nest
                if (isBag)
                    secondariesInBag.merge(ItemID.CRUSHED_NEST, item.getQuantity(), Integer::sum);
                else
                    secondariesInInventory.merge(ItemID.CRUSHED_NEST, item.getQuantity(), Integer::sum);
                continue;
            }

            // Check if this item is a secondary for any potion recipe
            if (isSecondaryIngredient(item.getId()))
            {
                if (isBag)
                    secondariesInBag.merge(item.getId(), item.getQuantity(), Integer::sum);
                else
                    secondariesInInventory.merge(item.getId(), item.getQuantity(), Integer::sum);
            }
        }
    }

    private boolean isSecondaryIngredient(int itemId)
    {
        for (PotionRecipe recipe : PotionRecipe.values())
        {
            if (recipe.getSecondaryItemId() == itemId)
            {
                return true;
            }
        }
        return false;
    }

    public int getTotalVials()
    {
        return vialsInBag + vialsInInventory;
    }

    /**
     * Get total count of a specific secondary across bag + inventory.
     */
    public int getSecondaryCount(int secondaryItemId)
    {
        return secondariesInBag.getOrDefault(secondaryItemId, 0)
            + secondariesInInventory.getOrDefault(secondaryItemId, 0);
    }

    /**
     * Calculate how many vials of water are needed for all grimy + clean herbs.
     * Unfinished potions don't need vials.
     */
    public int vialsNeeded(List<BagItem> herbItems)
    {
        int needed = 0;
        for (BagItem item : herbItems)
        {
            if (item.getState() == BagItem.ItemState.GRIMY
                || item.getState() == BagItem.ItemState.CLEAN)
            {
                needed += item.getQuantity();
            }
        }
        return needed;
    }

    /**
     * How many vials are missing (needed - have).
     */
    public int vialsMissing(List<BagItem> herbItems)
    {
        return Math.max(0, vialsNeeded(herbItems) - getTotalVials());
    }

    /**
     * Calculate how many of a given potion can actually be made,
     * limited by available secondaries.
     */
    public int maxPotionsPossible(PotionRecipe recipe, int herbCount)
    {
        int secondaryAvailable = getSecondaryCount(recipe.getSecondaryItemId());
        return Math.min(herbCount, secondaryAvailable);
    }

    /**
     * How many secondaries are missing for a recipe given herb count.
     */
    public int secondariesMissing(PotionRecipe recipe, int herbCount)
    {
        int available = getSecondaryCount(recipe.getSecondaryItemId());
        return Math.max(0, herbCount - available);
    }

    /**
     * Get display name for a secondary item.
     */
    public static String getSecondaryName(int itemId)
    {
        // Map common secondaries to readable names
        switch (itemId)
        {
            case ItemID.EYE_OF_NEWT: return "Eye of newt";
            case ItemID.UNICORN_HORN_DUST: return "Unicorn horn dust";
            case ItemID.LIMPWURT_ROOT: return "Limpwurt root";
            case ItemID.ASHES: return "Ashes";
            case ItemID.VOLCANIC_ASH: return "Volcanic ash";
            case ItemID.RED_SPIDERS_EGGS: return "Red spiders' eggs";
            case ItemID.CHOCOLATE_DUST: return "Chocolate dust";
            case ItemID.GOAT_HORN_DUST: return "Goat horn dust";
            case ItemID.WHITE_BERRIES: return "White berries";
            case ItemID.SNAPE_GRASS: return "Snape grass";
            case ItemID.TOADS_LEGS: return "Toad's legs";
            case ItemID.CRUSHED_NEST: return "Crushed nest";
            case ItemID.MORT_MYRE_FUNGUS: return "Mort myre fungus";
            case ItemID.KEBBIT_TEETH_DUST: return "Kebbit teeth dust";
            case ItemID.DRAGON_SCALE_DUST: return "Dragon scale dust";
            case ItemID.POTATO_CACTUS: return "Potato cactus";
            case ItemID.WINE_OF_ZAMORAK: return "Wine of zamorak";
            case ItemID.JANGERBERRIES: return "Jangerberries";
            default: return "Unknown (ID: " + itemId + ")";
        }
    }
}

package com.lootingbagherblore.data;

import lombok.AllArgsConstructor;
import lombok.Getter;

/**
 * Represents a herb-related item found in the looting bag.
 * Tracks its state (grimy/clean/unf) and quantity.
 */
@Getter
@AllArgsConstructor
public class BagItem
{
    private final HerbData herb;
    private final int itemId;
    private final int quantity;
    private final ItemState state;

    public enum ItemState
    {
        GRIMY,
        CLEAN,
        UNFINISHED
    }

    public static BagItem fromItemId(int itemId, int quantity)
    {
        HerbData herb = HerbData.fromGrimyId(itemId);
        if (herb != null)
        {
            return new BagItem(herb, itemId, quantity, ItemState.GRIMY);
        }

        herb = HerbData.fromCleanId(itemId);
        if (herb != null)
        {
            return new BagItem(herb, itemId, quantity, ItemState.CLEAN);
        }

        herb = HerbData.fromUnfId(itemId);
        if (herb != null)
        {
            return new BagItem(herb, itemId, quantity, ItemState.UNFINISHED);
        }

        return null;
    }

    /**
     * Get cleaning XP for this item (only if grimy).
     */
    public double getCleaningXp()
    {
        if (state == ItemState.GRIMY)
        {
            return herb.getCleanXp() * quantity;
        }
        return 0;
    }

    /**
     * Get potion-making XP for this item using a specific recipe.
     */
    public double getPotionXp(PotionRecipe recipe)
    {
        return recipe.getPotionXp() * quantity;
    }

    /**
     * Get total XP (cleaning + potion) for this item using a specific recipe.
     */
    public double getTotalXp(PotionRecipe recipe)
    {
        return getCleaningXp() + getPotionXp(recipe);
    }

    public String getDisplayName()
    {
        switch (state)
        {
            case GRIMY:
                return "Grimy " + herb.getDisplayName();
            case CLEAN:
                return herb.getDisplayName();
            case UNFINISHED:
                return herb.getDisplayName() + " potion (unf)";
            default:
                return herb.getDisplayName();
        }
    }
}

