		add(text, BorderLayout.CENTER);

		JButton copy = new JButton(CLIPBOARD_ICON);
		copy.setPreferredSize(new Dimension(40, 40));
		copy.setToolTipText("Copy result to clipboard");
		copy.addActionListener(e ->
