package com.truetilerenderer;

public enum NpcRenderMode {
  CURRENT_TARGET,
  CONFIGURED_LIST
}

package com.truetilerenderer;

import java.util.Arrays;
import java.util.Collections;
import java.util.LinkedHashSet;
import java.util.Locale;
import java.util.Set;
import java.util.stream.Collectors;
import net.runelite.api.Actor;
import net.runelite.api.NPC;
import net.runelite.api.NPCComposition;
import net.runelite.api.Player;

final class TrueTileActorMatcher {
  private TrueTileActorMatcher() {}

  static Set<String> parseConfiguredNpcNames(String rawNames) {
    if (rawNames == null || rawNames.isBlank()) {
      return Collections.emptySet();
    }

    return rawNames
        .lines()
        .flatMap(line -> Arrays.stream(line.split(",")))
        .map(String::trim)
        .filter(name -> !name.isEmpty())
        .map(TrueTileActorMatcher::normalizeName)
        .collect(Collectors.toCollection(LinkedHashSet::new));
  }

  static boolean shouldRenderNpc(
      NPC npc, Player localPlayer, NpcRenderMode renderMode, Set<String> configuredNpcNames) {
    if (npc == null
        || localPlayer == null
        || npc.getWorldLocation() == null
        || npc.getModel() == null) {
      return false;
    }

    if (renderMode == NpcRenderMode.CURRENT_TARGET) {
      Actor interacting = localPlayer.getInteracting();
      return interacting == npc || npc.getInteracting() == localPlayer;
    }

    String npcName = getNpcName(npc);
    return npcName != null && configuredNpcNames.contains(normalizeName(npcName));
  }

  static String getNpcName(NPC npc) {
    NPCComposition transformedComposition = npc.getTransformedComposition();
    if (transformedComposition != null && transformedComposition.getName() != null) {
      return transformedComposition.getName();
    }

    if (npc.getComposition() != null) {
      return npc.getComposition().getName();
    }

    return npc.getName();
  }

  static String normalizeName(String name) {
    return name.toLowerCase(Locale.ROOT);
  }
}

package com.truetilerenderer;

import com.google.inject.Provides;
import java.awt.Color;
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashSet;
import java.util.IdentityHashMap;
import java.util.Iterator;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import javax.inject.Inject;
import net.runelite.api.Actor;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.Hitsplat;
import net.runelite.api.NPC;
import net.runelite.api.Player;
import net.runelite.api.Renderable;
import net.runelite.api.RuneLiteObject;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import net.runelite.api.events.ActorDeath;
import net.runelite.api.events.GameStateChanged;
import net.runelite.api.events.HitsplatApplied;
import net.runelite.client.callback.Hooks;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.Subscribe;
import net.runelite.client.events.ConfigChanged;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.ui.overlay.OverlayManager;
import net.runelite.client.ui.overlay.outline.ModelOutlineRenderer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@PluginDescriptor(
    name = "True Tile Renderer",
    description =
        "Render true-tile outlines and mirrored overlays for the player and selected NPCs",
    tags = {"combat", "npc", "outline", "player", "true tile"})
public class TrueTileRendererPlugin extends Plugin {
  private static final Logger log = LoggerFactory.getLogger(TrueTileRendererPlugin.class);

  @Inject private Client client;

  @Inject private TrueTileRendererConfig config;

  @Inject private Hooks hooks;

  @Inject private OverlayManager overlayManager;

  @Inject private TrueTileRendererOverlay overlay;

  @Inject private ModelOutlineRenderer modelOutlineRenderer;

  @SuppressWarnings("deprecation")
  private final Hooks.RenderableDrawListener drawListener = this::shouldDraw;

  private final IdentityHashMap<Actor, RuneLiteObject> outlineObjects = new IdentityHashMap<>();
  private final IdentityHashMap<Actor, List<MirroredHitsplat>> mirroredHitsplats =
      new IdentityHashMap<>();
  private Set<String> configuredNpcNames = Collections.emptySet();
  private Set<NPC> trackedNpcs = Collections.emptySet();
  private boolean drawListenerErrorLogged;

  @Override
  @SuppressWarnings("deprecation")
  protected void startUp() {
    updateConfig();
    overlayManager.add(overlay);
    hooks.registerRenderableDrawListener(drawListener);
  }

  @Override
  @SuppressWarnings("deprecation")
  protected void shutDown() {
    hooks.unregisterRenderableDrawListener(drawListener);
    overlayManager.remove(overlay);
    clearTransientState();
  }

  @Subscribe
  public void onConfigChanged(ConfigChanged event) {
    if (TrueTileRendererConfig.GROUP.equals(event.getGroup())) {
      updateConfig();
    }
  }

  @Subscribe
  public void onHitsplatApplied(HitsplatApplied event) {
    if (!config.mirrorHitsplats()) {
      return;
    }

    Actor actor = event.getActor();
    Hitsplat hitsplat = event.getHitsplat();
    if (actor == null || hitsplat == null) {
      return;
    }

    if (!isTrackedActor(actor)) {
      mirroredHitsplats.remove(actor);
      return;
    }

    mirroredHitsplats
        .computeIfAbsent(actor, ignored -> new ArrayList<>())
        .add(
            new MirroredHitsplat(
                hitsplat.getHitsplatType(),
                hitsplat.getAmount(),
                hitsplat.getDisappearsOnGameCycle()));
  }

  @Subscribe
  public void onActorDeath(ActorDeath event) {
    if (event.getActor() != null) {
      mirroredHitsplats.remove(event.getActor());
    }
  }

  @Subscribe
  public void onGameStateChanged(GameStateChanged event) {
    if (event.getGameState() != GameState.LOGGED_IN) {
      clearTransientState();
    }
  }

  void renderOutlines() {
    if (client.getGameState() != GameState.LOGGED_IN) {
      clearTransientState();
      return;
    }

    Set<Actor> trackedActors = new HashSet<>();
    renderLocalPlayerOutline(trackedActors);
    trackedNpcs = collectTrackedNpcs();
    for (NPC npc : trackedNpcs) {
      trackedActors.add(npc);
      drawActorOutline(npc, config.npcOutlineColor());
    }

    pruneTransientState(trackedActors);
  }

  Set<NPC> getTrackedNpcs() {
    return trackedNpcs;
  }

  private Set<NPC> collectTrackedNpcs() {
    if (!config.renderNpcs()
        || client.getLocalPlayer() == null
        || client.getTopLevelWorldView() == null) {
      return Collections.emptySet();
    }

    Set<NPC> npcs = new LinkedHashSet<>();
    for (NPC npc : client.getTopLevelWorldView().npcs()) {
      if (TrueTileActorMatcher.shouldRenderNpc(
          npc, client.getLocalPlayer(), config.npcRenderMode(), configuredNpcNames)) {
        npcs.add(npc);
      }
    }
    return npcs;
  }

  List<MirroredHitsplat> getTrackedHitsplats(Actor actor) {
    if (actor == null) {
      return Collections.emptyList();
    }

    List<MirroredHitsplat> hitsplats = mirroredHitsplats.get(actor);
    if (hitsplats == null || hitsplats.isEmpty()) {
      return Collections.emptyList();
    }

    int currentCycle = client.getGameCycle();
    hitsplats.removeIf(hitsplat -> hitsplat.getDisappearsOnGameCycle() <= currentCycle);
    if (hitsplats.isEmpty()) {
      mirroredHitsplats.remove(actor);
      return Collections.emptyList();
    }

    return Collections.unmodifiableList(new ArrayList<>(hitsplats));
  }

  LocalPoint getTrueTileLocation(Actor actor) {
    WorldPoint worldLocation = actor.getWorldLocation();
    if (worldLocation == null) {
      return null;
    }

    return LocalPoint.fromWorld(actor.getWorldView(), worldLocation);
  }

  private void renderLocalPlayerOutline(Set<Actor> trackedActors) {
    if (!config.renderLocalPlayer()) {
      return;
    }

    Player localPlayer = client.getLocalPlayer();
    if (localPlayer != null) {
      trackedActors.add(localPlayer);
      drawActorOutline(localPlayer, config.playerOutlineColor());
    }
  }

  private void drawActorOutline(Actor actor, Color color) {
    LocalPoint trueTileLocation = getTrueTileLocation(actor);
    if (trueTileLocation == null) {
      return;
    }

    var model = actor.getModel();
    if (model == null) {
      return;
    }

    RuneLiteObject outlineObject =
        outlineObjects.computeIfAbsent(actor, ignored -> client.createRuneLiteObject());
    outlineObject.setModel(model);
    outlineObject.setLocation(trueTileLocation, actor.getWorldView().getPlane());
    outlineObject.setOrientation(actor.getCurrentOrientation());
    modelOutlineRenderer.drawOutline(
        outlineObject, config.outlineWidth(), color, config.outlineFeather());
  }

  private boolean shouldDraw(Renderable renderable, boolean drawingUi) {
    try {
      if (drawingUi) {
        return !(renderable instanceof Actor) || !shouldSuppressOriginalUi((Actor) renderable);
      }

      Player localPlayer = client.getLocalPlayer();
      return !(config.renderLocalPlayer() && renderable == localPlayer);
    } catch (RuntimeException ex) {
      if (!drawListenerErrorLogged) {
        log.warn("Failed to evaluate true-tile render visibility", ex);
        drawListenerErrorLogged = true;
      }
      return true;
    }
  }

  private boolean shouldSuppressOriginalUi(Actor actor) {
    if (!config.hideOriginalOverlays() || !isTrackedActor(actor)) {
      return false;
    }

    // Prevent duplicate overhead UI when the plugin is already redrawing those elements
    // at the actor's true-tile position.
    return config.mirrorActorNames()
        || config.mirrorHealthBars()
        || config.mirrorHeadIcons()
        || config.mirrorHitsplats();
  }

  private void pruneTransientState(Set<Actor> trackedActors) {
    pruneOutlineObjects(trackedActors);
    pruneMirroredHitsplats(trackedActors);
  }

  private void pruneOutlineObjects(Set<Actor> trackedActors) {
    Iterator<Actor> iterator = outlineObjects.keySet().iterator();
    while (iterator.hasNext()) {
      if (!trackedActors.contains(iterator.next())) {
        iterator.remove();
      }
    }
  }

  private void pruneMirroredHitsplats(Set<Actor> trackedActors) {
    int currentCycle = client.getGameCycle();
    Iterator<Map.Entry<Actor, List<MirroredHitsplat>>> iterator =
        mirroredHitsplats.entrySet().iterator();
    while (iterator.hasNext()) {
      Map.Entry<Actor, List<MirroredHitsplat>> entry = iterator.next();
      List<MirroredHitsplat> hitsplats = entry.getValue();
      hitsplats.removeIf(hitsplat -> hitsplat.getDisappearsOnGameCycle() <= currentCycle);
      if (!trackedActors.contains(entry.getKey()) || hitsplats.isEmpty()) {
        iterator.remove();
      }
    }
  }

  private boolean isTrackedActor(Actor actor) {
    if (actor == null) {
      return false;
    }

    if (actor == client.getLocalPlayer()) {
      return config.renderLocalPlayer();
    }

    if (actor instanceof NPC) {
      return config.renderNpcs()
          && TrueTileActorMatcher.shouldRenderNpc(
              (NPC) actor, client.getLocalPlayer(), config.npcRenderMode(), configuredNpcNames);
    }

    return false;
  }

  private void updateConfig() {
    configuredNpcNames = TrueTileActorMatcher.parseConfiguredNpcNames(config.npcNameList());
    if (!config.mirrorHitsplats()) {
      mirroredHitsplats.clear();
    }
    if (!config.renderNpcs()) {
      trackedNpcs = Collections.emptySet();
    }
  }

  private void clearTransientState() {
    outlineObjects.clear();
    mirroredHitsplats.clear();
    trackedNpcs = Collections.emptySet();
    drawListenerErrorLogged = false;
  }

  @Provides
  TrueTileRendererConfig provideConfig(ConfigManager configManager) {
    return configManager.getConfig(TrueTileRendererConfig.class);
  }

  static final class MirroredHitsplat {
    private final int hitsplatType;
    private final int amount;
    private final int disappearsOnGameCycle;

    private MirroredHitsplat(int hitsplatType, int amount, int disappearsOnGameCycle) {
      this.hitsplatType = hitsplatType;
      this.amount = amount;
      this.disappearsOnGameCycle = disappearsOnGameCycle;
    }

    int getHitsplatType() {
      return hitsplatType;
    }

    int getAmount() {
      return amount;
    }

    int getDisappearsOnGameCycle() {
      return disappearsOnGameCycle;
    }
  }
}

package com.truetilerenderer;

import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Font;
import java.awt.Graphics2D;
import java.awt.Stroke;
import java.awt.image.BufferedImage;
import java.util.ArrayList;
import java.util.List;
import java.util.Objects;
import javax.inject.Inject;
import net.runelite.api.Actor;
import net.runelite.api.Client;
import net.runelite.api.HeadIcon;
import net.runelite.api.HitsplatID;
import net.runelite.api.NPC;
import net.runelite.api.Perspective;
import net.runelite.api.Player;
import net.runelite.api.Point;
import net.runelite.api.SkullIcon;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.gameval.SpriteID;
import net.runelite.client.game.SpriteManager;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayUtil;

class TrueTileRendererOverlay extends Overlay {
  private static final int NAME_OFFSET = 40;
  private static final Color HEALTH_BAR_FILL = new Color(42, 170, 68, 220);
  private static final Color HEALTH_BAR_MISSING = new Color(120, 24, 24, 180);
  private static final Color HEALTH_BAR_BORDER = new Color(0, 0, 0, 220);
  private static final int HEALTH_BAR_WIDTH = 34;
  private static final int HEALTH_BAR_HEIGHT = 6;
  private static final BufferedImage HEALTH_BAR_ANCHOR =
      new BufferedImage(1, 1, BufferedImage.TYPE_INT_ARGB);
  private static final int ICON_SPACING = 2;
  private static final int HITSPLAT_VERTICAL_SPACING = 14;
  private static final int HITSPLAT_LIFETIME_BUFFER = 30;
  private static final Font HITSPLAT_FONT = new Font("Dialog", Font.BOLD, 16);

  private final Client client;
  private final TrueTileRendererPlugin plugin;
  private final TrueTileRendererConfig config;
  private final SpriteManager spriteManager;

  @Inject
  private TrueTileRendererOverlay(
      Client client,
      TrueTileRendererPlugin plugin,
      TrueTileRendererConfig config,
      SpriteManager spriteManager) {
    this.client = client;
    this.plugin = plugin;
    this.config = config;
    this.spriteManager = spriteManager;
    setPosition(OverlayPosition.DYNAMIC);
    setLayer(OverlayLayer.ABOVE_SCENE);
  }

  @Override
  public Dimension render(Graphics2D graphics) {
    plugin.renderOutlines();

    if (config.renderLocalPlayer()) {
      renderActorText(graphics, client.getLocalPlayer());
    }

    if (config.renderNpcs()) {
      for (Actor actor : plugin.getTrackedNpcs()) {
        renderActorText(graphics, actor);
      }
    }

    return null;
  }

  private void renderActorText(Graphics2D graphics, Actor actor) {
    if (actor == null) {
      return;
    }

    LocalPoint trueTileLocation = plugin.getTrueTileLocation(actor);
    if (trueTileLocation == null) {
      return;
    }

    if (config.mirrorActorNames()) {
      String actorName = actor.getName();
      if (actorName != null && !actorName.isBlank()) {
        Client safeClient = Objects.requireNonNull(client);
        Graphics2D safeGraphics = Objects.requireNonNull(graphics);
        LocalPoint safeTrueTileLocation = Objects.requireNonNull(trueTileLocation);
        Point nameLocation =
            Perspective.getCanvasTextLocation(
                safeClient,
                safeGraphics,
                safeTrueTileLocation,
                actorName,
                actor.getLogicalHeight() + NAME_OFFSET + getExtraVerticalOffset(actor));
        OverlayUtil.renderTextLocation(graphics, nameLocation, actorName, getTextColor(actor));
      }
    }

    if (config.mirrorHealthBars()) {
      renderHealthBar(graphics, actor, trueTileLocation);
    }

    if (config.mirrorHeadIcons()) {
      renderHeadIcons(graphics, actor, trueTileLocation);
    }

    if (config.mirrorHitsplats()) {
      renderHitsplats(graphics, actor, trueTileLocation);
    }
  }

  private Color getTextColor(Actor actor) {
    if (actor instanceof Player) {
      return config.playerOutlineColor();
    }

    return config.npcOutlineColor();
  }

  private int getExtraVerticalOffset(Actor actor) {
    int offset = 0;
    if (config.mirrorHealthBars() && actor.getHealthScale() > 0 && actor.getHealthRatio() >= 0) {
      offset += 14;
    }

    if (config.mirrorHeadIcons() && !getHeadIconImages(actor).isEmpty()) {
      offset += 20;
    }

    if (config.mirrorHitsplats() && !plugin.getTrackedHitsplats(actor).isEmpty()) {
      offset += 18;
    }

    return offset;
  }

  private void renderHealthBar(Graphics2D graphics, Actor actor, LocalPoint trueTileLocation) {
    int healthScale = actor.getHealthScale();
    int healthRatio = actor.getHealthRatio();
    if (healthScale <= 0 || healthRatio < 0) {
      return;
    }

    int clampedRatio = Math.min(healthRatio, healthScale);
    int fillWidth = Math.round((clampedRatio / (float) healthScale) * HEALTH_BAR_WIDTH);
    Client safeClient = Objects.requireNonNull(client);
    LocalPoint safeTrueTileLocation = Objects.requireNonNull(trueTileLocation);
    Point location =
        Perspective.getCanvasImageLocation(
            safeClient, safeTrueTileLocation, HEALTH_BAR_ANCHOR, actor.getLogicalHeight() + 34);
    if (location == null) {
      return;
    }

    int x = location.getX() - (HEALTH_BAR_WIDTH / 2);
    int y = location.getY();
    Color originalColor = graphics.getColor();
    Stroke originalStroke = graphics.getStroke();

    graphics.setColor(HEALTH_BAR_BORDER);
    graphics.setStroke(new BasicStroke(1f));
    graphics.drawRect(x - 1, y - 1, HEALTH_BAR_WIDTH + 1, HEALTH_BAR_HEIGHT + 1);
    graphics.setColor(HEALTH_BAR_MISSING);
    graphics.fillRect(x, y, HEALTH_BAR_WIDTH, HEALTH_BAR_HEIGHT);
    graphics.setColor(HEALTH_BAR_FILL);
    graphics.fillRect(x, y, fillWidth, HEALTH_BAR_HEIGHT);
    graphics.setColor(originalColor);
    graphics.setStroke(originalStroke);
  }

  private void renderHeadIcons(Graphics2D graphics, Actor actor, LocalPoint trueTileLocation) {
    List<BufferedImage> icons = getHeadIconImages(actor);
    if (icons.isEmpty()) {
      return;
    }

    int totalWidth =
        icons.stream().mapToInt(BufferedImage::getWidth).sum()
            + ICON_SPACING * Math.max(0, icons.size() - 1);
    int startXOffset = -(totalWidth / 2);
    int runningXOffset = 0;
    int zOffset = actor.getLogicalHeight() + 52;

    for (BufferedImage icon : icons) {
      Client safeClient = Objects.requireNonNull(client);
      LocalPoint safeTrueTileLocation = Objects.requireNonNull(trueTileLocation);
      BufferedImage safeIcon = Objects.requireNonNull(icon);
      Point location =
          Perspective.getCanvasImageLocation(safeClient, safeTrueTileLocation, safeIcon, zOffset);
      if (location != null) {
        Point shifted = new Point(location.getX() + startXOffset + runningXOffset, location.getY());
        OverlayUtil.renderImageLocation(graphics, shifted, icon);
      }
      runningXOffset += icon.getWidth() + ICON_SPACING;
    }
  }

  private List<BufferedImage> getHeadIconImages(Actor actor) {
    List<BufferedImage> images = new ArrayList<>();
    if (actor instanceof Player) {
      Player player = (Player) actor;
      addIfPresent(images, getSkullImage(player.getSkullIcon()));
      addIfPresent(images, getPrayerImage(player.getOverheadIcon()));
    } else if (actor instanceof NPC) {
      NPC npc = (NPC) actor;
      int[] archiveIds = npc.getOverheadArchiveIds();
      short[] spriteIds = npc.getOverheadSpriteIds();
      if (archiveIds != null && spriteIds != null) {
        for (int i = 0; i < Math.min(archiveIds.length, spriteIds.length); i++) {
          if (archiveIds[i] >= 0 && spriteIds[i] >= 0) {
            addIfPresent(images, spriteManager.getSprite(archiveIds[i], spriteIds[i]));
          }
        }
      }
    }
    return images;
  }

  private void addIfPresent(List<BufferedImage> images, BufferedImage image) {
    if (image != null) {
      images.add(image);
    }
  }

  private BufferedImage getPrayerImage(HeadIcon headIcon) {
    if (headIcon == null) {
      return null;
    }

    switch (headIcon) {
      case MELEE:
        return spriteManager.getSprite(SpriteID.Prayeron.PROTECT_FROM_MELEE, 0);
      case RANGED:
        return spriteManager.getSprite(SpriteID.Prayeron.PROTECT_FROM_MISSILES, 0);
      case MAGIC:
        return spriteManager.getSprite(SpriteID.Prayeron.PROTECT_FROM_MAGIC, 0);
      case RETRIBUTION:
        return spriteManager.getSprite(SpriteID.Prayeron.RETRIBUTION, 0);
      case SMITE:
        return spriteManager.getSprite(SpriteID.Prayeron.SMITE, 0);
      case REDEMPTION:
        return spriteManager.getSprite(SpriteID.Prayeron.REDEMPTION, 0);
      case WRATH:
        return spriteManager.getSprite(SpriteID.IconPrayerZaros01_30x30.WRATH, 0);
      default:
        return null;
    }
  }

  private BufferedImage getSkullImage(int skullIcon) {
    switch (skullIcon) {
      case SkullIcon.SKULL:
        return spriteManager.getSprite(SpriteID.HeadiconsPkInterface.PLAYER_KILLER_SKULL, 0);
      case SkullIcon.SKULL_FIGHT_PIT:
        return spriteManager.getSprite(
            SpriteID.HeadiconsPkInterface.FIGHT_PITS_WINNER_SKULL_RED, 0);
      default:
        return null;
    }
  }

  private void renderHitsplats(Graphics2D graphics, Actor actor, LocalPoint trueTileLocation) {
    List<TrueTileRendererPlugin.MirroredHitsplat> hitsplats = plugin.getTrackedHitsplats(actor);
    if (hitsplats.isEmpty()) {
      return;
    }

    Font originalFont = graphics.getFont();
    Color originalColor = graphics.getColor();
    graphics.setFont(HITSPLAT_FONT);
    int currentCycle = client.getGameCycle();

    for (int i = 0; i < hitsplats.size(); i++) {
      TrueTileRendererPlugin.MirroredHitsplat hitsplat = hitsplats.get(i);
      String text = Integer.toString(hitsplat.getAmount());
      int remainingCycles = Math.max(0, hitsplat.getDisappearsOnGameCycle() - currentCycle);
      int riseOffset =
          Math.min(
              18,
              (HITSPLAT_LIFETIME_BUFFER - Math.min(HITSPLAT_LIFETIME_BUFFER, remainingCycles)) / 2);
      int alpha = Math.min(255, Math.max(90, remainingCycles * 8));
      int zOffset = actor.getLogicalHeight() + 72 + (i * HITSPLAT_VERTICAL_SPACING) + riseOffset;

      Client safeClient = Objects.requireNonNull(client);
      Graphics2D safeGraphics = Objects.requireNonNull(graphics);
      LocalPoint safeTrueTileLocation = Objects.requireNonNull(trueTileLocation);
      Point textLocation =
          Perspective.getCanvasTextLocation(
              safeClient, safeGraphics, safeTrueTileLocation, text, zOffset);
      if (textLocation != null) {
        OverlayUtil.renderTextLocation(
            graphics,
            textLocation,
            text,
            withAlpha(getHitsplatColor(hitsplat.getHitsplatType()), alpha));
      }
    }

    graphics.setFont(originalFont);
    graphics.setColor(originalColor);
  }

  private Color getHitsplatColor(int hitsplatType) {
    switch (hitsplatType) {
      case HitsplatID.BLOCK_ME:
      case HitsplatID.BLOCK_OTHER:
        return new Color(96, 160, 255);
      case HitsplatID.POISON:
      case HitsplatID.VENOM:
      case HitsplatID.DISEASE:
      case HitsplatID.DISEASE_BLOCKED:
        return new Color(64, 224, 96);
      case HitsplatID.HEAL:
        return new Color(120, 255, 120);
      case HitsplatID.PRAYER_DRAIN:
        return new Color(170, 120, 255);
      case HitsplatID.BLEED:
      case HitsplatID.BURN:
        return new Color(255, 120, 64);
      case HitsplatID.CORRUPTION:
      case HitsplatID.SANITY_DRAIN:
      case HitsplatID.DOOM:
        return new Color(200, 80, 200);
      default:
        return new Color(255, 255, 255);
    }
  }

  private Color withAlpha(Color color, int alpha) {
    return new Color(color.getRed(), color.getGreen(), color.getBlue(), alpha);
  }
}

