package com.slowscape;

final class SlowScapeBlockAlertView
{
	private static final String FIRST_ACTION_PREFIX = "Already spent on: ";
	private static final int DETAIL_LIMIT = 56;

	private final String title;
	private final String reason;
	private final String detail;

	private SlowScapeBlockAlertView(String title, String reason, String detail)
	{
		this.title = title;
		this.reason = reason;
		this.detail = detail;
	}

	static SlowScapeBlockAlertView from(String message)
	{
		String cleanMessage = message == null ? "" : message.trim();
		String detail = "";
		if (cleanMessage.startsWith(FIRST_ACTION_PREFIX))
		{
			detail = shorten("First action: " + cleanMessage.substring(FIRST_ACTION_PREFIX.length()));
		}

		return new SlowScapeBlockAlertView("Action blocked", "Today's action is already spent", detail);
	}

	String getTitle()
	{
		return title;
	}

	String getReason()
	{
		return reason;
	}

	String getDetail()
	{
		return detail;
	}

	private static String shorten(String value)
	{
		if (value.length() <= DETAIL_LIMIT)
		{
			return value;
		}

		return value.substring(0, DETAIL_LIMIT - 3).trim() + "...";
	}
}

package com.slowscape;

final class SlowScapeSnapshotChangeTracker
{
	private String lastSnapshot;

	boolean observe(String snapshot)
	{
		String current = snapshot == null ? "" : snapshot;
		if (lastSnapshot == null)
		{
			lastSnapshot = current;
			return false;
		}

		if (lastSnapshot.equals(current))
		{
			return false;
		}

		lastSnapshot = current;
		return true;
	}

	void reset()
	{
		lastSnapshot = null;
	}
}

package com.slowscape;

import java.time.Instant;
import java.time.LocalDate;
import java.util.function.Supplier;

final class SlowScapeDailyTracker
{
	private final SlowScapeStateStore stateStore;
	private final Supplier<LocalDate> todaySupplier;
	private final Supplier<Instant> nowSupplier;

	SlowScapeDailyTracker(SlowScapeStateStore stateStore, Supplier<LocalDate> todaySupplier, Supplier<Instant> nowSupplier)
	{
		this.stateStore = stateStore;
		this.todaySupplier = todaySupplier;
		this.nowSupplier = nowSupplier;
	}

	SlowScapeActionGateResult trySpend(String actionSummary, boolean allowExtraActionsToday)
	{
		LocalDate today = todaySupplier.get();
		SlowScapeDailyRecord record = loadToday(today);
		if (!record.hasSpentAction())
		{
			SlowScapeDailyRecord updated = record.recordAction(today, nowSupplier.get(), actionSummary);
			stateStore.save(updated);
			return SlowScapeActionGateResult.allowed(updated, false);
		}

		if (allowExtraActionsToday)
		{
			SlowScapeDailyRecord updated = record.recordAction(today, nowSupplier.get(), actionSummary);
			stateStore.save(updated);
			return SlowScapeActionGateResult.allowed(updated, true);
		}

		return SlowScapeActionGateResult.blocked(record);
	}

	boolean recordIfUnspent(String actionSummary)
	{
		LocalDate today = todaySupplier.get();
		SlowScapeDailyRecord record = loadToday(today);
		if (record.hasSpentAction())
		{
			return false;
		}

		stateStore.save(record.recordAction(today, nowSupplier.get(), actionSummary));
		return true;
	}

	boolean hasSpentToday()
	{
		return loadToday(todaySupplier.get()).hasSpentAction();
	}

	SlowScapeDailyRecord snapshot()
	{
		return loadToday(todaySupplier.get());
	}

	void resetToday()
	{
		stateStore.save(SlowScapeDailyRecord.empty().forDate(todaySupplier.get()));
	}

	private SlowScapeDailyRecord loadToday(LocalDate today)
	{
		SlowScapeDailyRecord record = stateStore.load();
		SlowScapeDailyRecord todayRecord = record.forDate(today);
		if (!todayRecord.isForDate(today) || !todayRecord.getDate().equals(record.getDate()))
		{
			stateStore.save(todayRecord);
		}
		return todayRecord;
	}
}

package com.slowscape;

import java.time.Duration;
import java.time.Instant;
import java.time.ZoneId;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

final class SlowScapeOverlayModel
{
	private static final DateTimeFormatter UNLOCK_FORMATTER = DateTimeFormatter
		.ofPattern("MMM d h:mm a", Locale.US);

	private final ZoneId zoneId;

	SlowScapeOverlayModel(ZoneId zoneId)
	{
		this.zoneId = zoneId;
	}

	List<SlowScapeOverlayLine> lines(
		SlowScapeDailyRecord record,
		boolean override,
		boolean showUnlockTimer,
		Instant now,
		Instant nextUnlock)
	{
		List<SlowScapeOverlayLine> lines = new ArrayList<>();
		boolean spent = record.hasSpentAction();

		lines.add(new SlowScapeOverlayLine("Date", record.getDate()));
		lines.add(new SlowScapeOverlayLine("Status", override ? "Override" : spent ? "Spent" : "Available"));
		lines.add(new SlowScapeOverlayLine("Actions", Integer.toString(record.getActionCount())));

		if (showUnlockTimer)
		{
			lines.add(new SlowScapeOverlayLine("Unlocks", UNLOCK_FORMATTER.format(nextUnlock.atZone(zoneId))));
			lines.add(new SlowScapeOverlayLine("Time left", formatRemaining(now, nextUnlock)));
		}

		if (override && record.getActionCount() > 1)
		{
			lines.add(new SlowScapeOverlayLine("Extra used", Integer.toString(record.getActionCount() - 1)));
		}

		if (spent)
		{
			lines.add(new SlowScapeOverlayLine("First", record.getFirstAction()));
		}

		return lines;
	}

	private static String formatRemaining(Instant now, Instant nextUnlock)
	{
		Duration duration = Duration.between(now, nextUnlock);
		if (duration.isNegative() || duration.isZero())
		{
			return "0m";
		}

		long totalMinutes = duration.toMinutes();
		long days = totalMinutes / (24 * 60);
		long hours = (totalMinutes % (24 * 60)) / 60;
		long minutes = totalMinutes % 60;
		if (days > 0)
		{
			return days + "d " + hours + "h";
		}
		if (hours > 0)
		{
			return hours + "h " + minutes + "m";
		}
		return minutes + "m";
	}
}

package com.slowscape;

import java.awt.Color;
import java.awt.Dimension;
import java.awt.FontMetrics;
import java.awt.Graphics2D;
import java.time.Instant;
import javax.inject.Inject;
import net.runelite.client.ui.overlay.OverlayPanel;
import net.runelite.client.ui.overlay.OverlayPosition;

final class SlowScapeBlockedActionOverlay extends OverlayPanel
{
	private static final Color BACKGROUND = new Color(45, 27, 24, 235);
	private static final Color BORDER = new Color(28, 16, 14, 245);
	private static final Color BLOCKED = new Color(255, 126, 92);
	private static final Color TEXT = new Color(245, 239, 232);
	private static final Color MUTED = new Color(218, 190, 178);
	private static final int ALERT_WIDTH = 520;

	private final SlowScapePlugin plugin;
	private final SlowScapeConfig config;

	@Inject
	SlowScapeBlockedActionOverlay(SlowScapePlugin plugin, SlowScapeConfig config)
	{
		super(plugin);
		this.plugin = plugin;
		this.config = config;
		setPosition(OverlayPosition.TOP_CENTER);
		setPreferredSize(new Dimension(ALERT_WIDTH, 0));
		setResizable(false);
	}

	@Override
	public Dimension render(Graphics2D graphics)
	{
		if (!config.showBlockedActionAlert())
		{
			return null;
		}

		String message = plugin.getBlockedActionAlertMessage(Instant.now());
		if (message.isEmpty())
		{
			return null;
		}
		SlowScapeBlockAlertView view = SlowScapeBlockAlertView.from(message);
		SlowScapeBlockedActionLayout layout = SlowScapeBlockedActionLayout.from(view, graphics.getFontMetrics());

		graphics.setColor(BACKGROUND);
		graphics.fillRect(0, 0, layout.getWidth(), layout.getHeight());
		graphics.setColor(BORDER);
		graphics.drawRect(0, 0, layout.getWidth() - 1, layout.getHeight() - 1);

		FontMetrics metrics = graphics.getFontMetrics();
		int baseline = SlowScapeBlockedActionLayout.VERTICAL_PADDING + metrics.getAscent();
		for (int i = 0; i < layout.getLines().size(); i++)
		{
			SlowScapeBlockedActionLayout.Line line = layout.getLines().get(i);
			Color color = i == 0 ? BLOCKED : i == 1 ? TEXT : MUTED;
			drawCenteredText(graphics, line.getText(), color, baseline, layout.getWidth());
			baseline += metrics.getHeight() + SlowScapeBlockedActionLayout.LINE_GAP;
		}

		return new Dimension(layout.getWidth(), layout.getHeight());
	}

	private static void drawCenteredText(Graphics2D graphics, String text, Color color, int baseline, int width)
	{
		FontMetrics metrics = graphics.getFontMetrics();
		int x = (width - metrics.stringWidth(text)) / 2;
		drawShadowedText(graphics, text, color, x, baseline);
	}

	private static void drawShadowedText(Graphics2D graphics, String text, Color color, int x, int baseline)
	{
		graphics.setColor(Color.BLACK);
		graphics.drawString(text, x + 1, baseline + 1);
		graphics.setColor(color);
		graphics.drawString(text, x, baseline);
	}
}

package com.slowscape;

import java.awt.Color;
import java.awt.Dimension;
import java.awt.FontMetrics;
import java.awt.Graphics2D;
import java.time.Instant;
import java.time.ZoneId;
