		this.right = right;
	}

	String getLeft()
	{
		return left;
	}

	String getRight()
	{
		return right;
	}

	@Override
	public boolean equals(Object other)
	{
		if (this == other)
		{
			return true;
		}

		if (!(other instanceof SlowScapeOverlayLine))
		{
			return false;
